class Boss extends Entity {
    damageDealtBy: Map<number, number> = new Map();
    spawnTimer: number = 0;
    phaseTimer: number = 0;
    xpValue: number = 500000;

    constructor(id: number) {
        super(id, EntityType.BOSS, CANVAS_WIDTH / 2, CANVAS_HEIGHT / 2, 180, '#0055ff');
        this.maxHealth = 150000;
        this.health = this.maxHealth;
        this.displayHealth = this.maxHealth;
        this.damage = 150;
        this.mass = 15000;
        this.friction = 0.99;
        this.name = "GRAND SINGULARITY";
        this.pos.x += Vector.randomRange(-100, 100);
        this.pos.y += Vector.randomRange(-100, 100);
    }

    override takeDamage(amount: number, sourceId: number | null = null) {
        if (sourceId !== null && amount > 0) this.damageDealtBy.set(sourceId, (this.damageDealtBy.get(sourceId) || 0) + amount);
        super.takeDamage(amount, sourceId);
    }

    override update(dt: number) { 
        this.phaseTimer += dt;
        const hpRatio = this.health / this.maxHealth;
        this.rotation += (0.8 + (1 - hpRatio) * 1.2) * dt; 

        if (Date.now() - this.lastDamageTime > 10000) {
            this.health = Math.min(this.health + 50 * dt * 60, this.maxHealth);
        }

        super.update(dt); 
    }

    override drawBody(ctx: CanvasRenderingContext2D) {
        const t = Date.now() / 1000;
        const hpRatio = this.health / this.maxHealth;

        ctx.save();
        const auraSize = this.radius * (1.3 + Math.sin(t * 2) * 0.08);
        const grad = ctx.createRadialGradient(0, 0, this.radius * 0.8, 0, 0, auraSize);
        grad.addColorStop(0, 'rgba(0, 85, 255, 0.4)');
        grad.addColorStop(0.6, 'rgba(0, 20, 100, 0.2)');
        grad.addColorStop(1, 'rgba(0, 0, 0, 0)');
        ctx.fillStyle = grad;
        ctx.beginPath(); ctx.arc(0, 0, auraSize, 0, Math.PI * 2); ctx.fill();
        ctx.restore();

        for (let j = 0; j < 2; j++) {
            ctx.save();
            ctx.rotate(j === 0 ? t * 0.5 : -t * 0.8);
            ctx.beginPath();
            for (let i = 0; i < 5; i++) {
                const angle = (i * 2 * Math.PI) / 5;
                const r = this.radius * (1.1 + j * 0.2);
                const x = Math.cos(angle) * r;
                const y = Math.sin(angle) * r;
                if (i === 0) ctx.moveTo(x, y);
                else ctx.lineTo(x, y);
            }
            ctx.closePath();
            ctx.lineWidth = 12;
            ctx.strokeStyle = j === 0 ? 'rgba(0, 178, 225, 0.6)' : 'rgba(118, 141, 252, 0.4)';
            ctx.stroke();
            ctx.restore();
        }

        ctx.beginPath();
        for (let i = 0; i < 5; i++) {
            const angle = (i * 2 * Math.PI) / 5;
            const x = Math.cos(angle) * this.radius;
            const y = Math.sin(angle) * this.radius;
            if (i === 0) ctx.moveTo(x, y);
            else ctx.lineTo(x, y);
        }
        ctx.closePath();

        const r = Math.floor((1 - hpRatio) * 150);
        const g = Math.floor(hpRatio * 150);
        const b = 255;
        ctx.fillStyle = `rgb(${r}, ${g}, ${b})`;
        ctx.fill();

        ctx.lineWidth = 15;
        ctx.strokeStyle = COLORS.border;
        ctx.stroke();

        ctx.beginPath();
        ctx.arc(0, 0, this.radius * 0.3 * (1 + Math.sin(t * 10) * 0.1), 0, Math.PI * 2);
        ctx.fillStyle = '#fff';
        ctx.shadowBlur = 40;
        ctx.shadowColor = '#0ff';
        ctx.fill();
    }
}

class Shape extends Entity {
  shapeType: ShapeType;
  xpValue: number;
  driftVec: Vector2;
  rarity: ShapeRarity;
  damageDealtBy: Map<number, number> = new Map();
  hueTimer: number = 0; 
  pulseTimer: number = 0;
  ambientTimer: number = 0;

  constructor(id: number, x: number, y: number, type: ShapeType) {
    const stats = SHAPE_STATS[type];
    const roll = Math.random();

    let rarity = ShapeRarity.COMMON;
    let accumulated = 0;
    const rarities = Object.values(ShapeRarity);
    for (const r of rarities) {
        const chance = RARITY_CONFIG[r].chance;
        accumulated += chance;
        if (roll < accumulated) {
            rarity = r;
            break;
        }
    }

    const rarityConfig = RARITY_CONFIG[rarity];
    super(id, EntityType.SHAPE, x, y, stats.radius * rarityConfig.sizeMult, rarityConfig.color || stats.color);
    this.team = Team.NONE;
    this.friction = 0.95; 
    this.shapeType = type;
    this.rarity = rarity;
    this.maxHealth = Math.floor(stats.health * rarityConfig.hpMult);
    this.health = this.maxHealth;
    this.displayHealth = this.maxHealth;
    this.xpValue = Math.floor(stats.xp * rarityConfig.xpMult);
    this.damage = stats.damage; 
    this.mass = this.radius * 2.5;
    this.vel = { x: Vector.randomRange(-0.2, 0.2), y: Vector.randomRange(-0.2, 0.2) };
    const driftAngle = Math.random() * Math.PI * 2;
    this.driftVec = { x: Math.cos(driftAngle) * 0.005, y: Math.sin(driftAngle) * 0.005 };
    this.hueTimer = Math.random() * 360;
    this.pulseTimer = Math.random() * Math.PI * 2;
    this.ambientTimer = Math.random() * 1000;
  }

  override takeDamage(amount: number, sourceId: number | null = null) {
      if (sourceId !== null && amount > 0) this.damageDealtBy.set(sourceId, (this.damageDealtBy.get(sourceId) || 0) + amount);
      super.takeDamage(amount, sourceId);
  }

  override update(dt: number) {
    this.rotation += 0.015;
    this.acc.x += this.driftVec.x;
    this.acc.y += this.driftVec.y;
    this.pulseTimer += dt * 3; 

    this.visualScale = 1.0 + Math.sin(this.pulseTimer) * 0.04;

    if (this.rarity === ShapeRarity.TRANSCENDENT) { this.hueTimer += dt * 120; this.rotation += 0.025; }
    else if (this.rarity === ShapeRarity.ETERNAL || this.rarity === ShapeRarity.MYTHICAL) this.rotation += 0.04;
    else if (this.rarity === ShapeRarity.EPIC) this.rotation += 0.01;
    super.update(dt);
  }

  override drawBody(ctx: CanvasRenderingContext2D) {
    const sides = SHAPE_STATS[this.shapeType].sides;

    if (this.rarity === ShapeRarity.TRANSCENDENT) {
        this.drawTranscendentBody(ctx, sides);
        return;
    }

    ctx.save();
    let fillColor = this.color;
    let strokeColor = COLORS.border;
    let glowColor = 'transparent';
    let glowBlur = 0;

    switch (this.rarity) {
        case ShapeRarity.UNCOMMON: strokeColor = '#4db8ff'; glowColor = '#4db8ff'; glowBlur = 12; break;
        case ShapeRarity.RARE: strokeColor = '#00ff80'; glowColor = '#00ff80'; glowBlur = 25; break;
        case ShapeRarity.EPIC: fillColor = '#ffd700'; strokeColor = '#ffaa00'; glowColor = '#ffcc00'; glowBlur = 40; break;
        case ShapeRarity.LEGENDARY: fillColor = '#ff5e00'; strokeColor = '#ff0000'; glowColor = '#ff5e00'; glowBlur = 55; break;
        case ShapeRarity.MYTHICAL: fillColor = '#1a002b'; strokeColor = '#a200ff'; glowColor = '#a200ff'; glowBlur = 70; break;
        case ShapeRarity.ETERNAL: fillColor = '#f0ffff'; strokeColor = '#00ffff'; glowColor = '#00ffff'; glowBlur = 95; break;
    }

    if (this.rarity === ShapeRarity.UNCOMMON) this.drawUncommonVisuals(ctx);
    if (this.rarity === ShapeRarity.RARE) this.drawRareVisuals(ctx);
    if (this.rarity === ShapeRarity.EPIC) this.drawEpicVisuals(ctx);
    if (this.rarity === ShapeRarity.LEGENDARY) this.drawLegendaryVisuals(ctx);
    if (this.rarity === ShapeRarity.MYTHICAL) this.drawMythicalVisuals(ctx);
    if (this.rarity === ShapeRarity.ETERNAL) this.drawEternalVisuals(ctx);

    if (glowBlur > 0) { ctx.shadowBlur = glowBlur; ctx.shadowColor = glowColor; }
    this.traceShape(ctx, sides, this.radius);

    const glintPos = (Math.sin(Date.now() / 2000) + 1) / 2; 
    const grad = ctx.createLinearGradient(-this.radius * 2, -this.radius * 2, this.radius * 2, this.radius * 2);

    if (this.rarity !== ShapeRarity.COMMON) {
        grad.addColorStop(0, fillColor);
        grad.addColorStop(Math.max(0, glintPos - 0.1), fillColor);
        grad.addColorStop(glintPos, 'rgba(255,255,255,0.4)');
        grad.addColorStop(Math.min(1, glintPos + 0.1), fillColor);
        grad.addColorStop(1, fillColor);
        ctx.fillStyle = grad;
    } else {
        ctx.fillStyle = fillColor;
    }

    ctx.fill(); 
    ctx.shadowBlur = 0; 
    ctx.lineWidth = 3; 
    ctx.strokeStyle = strokeColor; 
    ctx.stroke();
    ctx.restore();
  }

  private drawTranscendentBody(ctx: CanvasRenderingContext2D, sides: number) {
    const hue = Math.floor(this.hueTimer % 360);
    const t = Date.now() / 1000;
    const isGlitching = Math.sin(t * 15) > 0.8;
    const glitchOffset = isGlitching ? (Math.random() - 0.5) * 16 : Math.sin(this.pulseTimer * 18) * 2;

    ctx.save();
    ctx.save(); 
    ctx.translate(-glitchOffset, isGlitching ? glitchOffset/2 : 0); 
    ctx.globalAlpha = 0.6; 
    this.traceShape(ctx, sides, this.radius); 
    ctx.lineWidth = 5; ctx.strokeStyle = 'cyan'; ctx.stroke(); 
    ctx.restore();

    ctx.save(); 
    ctx.translate(glitchOffset, isGlitching ? -glitchOffset/2 : 0); 
    ctx.globalAlpha = 0.6; 
    this.traceShape(ctx, sides, this.radius); 
    ctx.lineWidth = 5; ctx.strokeStyle = 'magenta'; ctx.stroke(); 
    ctx.restore();

    this.traceShape(ctx, sides, this.radius);
    ctx.fillStyle = '#080808'; ctx.fill();
    ctx.save(); ctx.clip();

    const scanY = ((t * 3) % 1.5) * this.radius * 4 - this.radius * 2;
    ctx.fillStyle = `hsla(${hue}, 100%, 85%, ${isGlitching ? 0.7 : 0.3})`;
    ctx.fillRect(-this.radius * 2.5, scanY, this.radius * 5, 4);

    const seed = Math.floor(Date.now() / 100);
    const rng = (i: number) => { const x = Math.sin(seed + i) * 10000; return x - Math.floor(x); };
    ctx.fillStyle = `hsl(${hue}, 100%, 75%)`;
    for(let i=0; i < (isGlitching ? 32 : 16); i++) {
        const sx = (rng(i) - 0.5) * this.radius * 2.4;
        const sy = (rng(i+60) - 0.5) * this.radius * 2.4;
        const sz = rng(i+120) * 6;
        ctx.fillRect(sx, sy, sz, sz);
    }
    ctx.restore();

    ctx.lineWidth = 5;
    ctx.strokeStyle = `hsl(${hue}, 100%, 70%)`;
    ctx.shadowColor = `hsl(${hue}, 100%, 50%)`;
    ctx.shadowBlur = isGlitching ? 50 : 30;
    ctx.stroke();
    ctx.restore();
  }

  traceShape(ctx: CanvasRenderingContext2D, sides: number, radius: number) { ctx.beginPath(); for (let i = 0; i < sides; i++) { const angle = (i * 2 * Math.PI) / sides; const x = Math.cos(angle) * radius; const y = Math.sin(angle) * radius; if (i === 0) ctx.moveTo(x, y); else ctx.lineTo(x, y); } ctx.closePath(); }

  drawUncommonVisuals(ctx: CanvasRenderingContext2D) {
    const t = Date.now() / 1000;
    const sides = SHAPE_STATS[this.shapeType].sides;
    const bracketPulse = 1.0 + Math.sin(t * 6) * 0.1;

    ctx.save();
    ctx.strokeStyle = '#4db8ff';
    ctx.lineWidth = 4;
    ctx.lineCap = 'round';

    for (let i = 0; i < sides; i++) {
        const angle = (i * 2 * Math.PI) / sides;
        const dist = this.radius * 1.25 * bracketPulse;
        const x = Math.cos(angle) * dist;
        const y = Math.sin(angle) * dist;

        ctx.save();
        ctx.translate(x, y);
        ctx.rotate(angle);
        ctx.beginPath();
        ctx.moveTo(-6, -6);
        ctx.lineTo(0, 0);
        ctx.lineTo(-6, 6);
        ctx.stroke();
        ctx.restore();
    }

    ctx.save();
    this.traceShape(ctx, sides, this.radius);
    ctx.clip();
    ctx.strokeStyle = 'rgba(77, 184, 255, 0.15)';
    ctx.lineWidth = 1;
    for(let i = -this.radius; i < this.radius; i += 8) {
        ctx.beginPath(); ctx.moveTo(i, -this.radius); ctx.lineTo(i, this.radius); ctx.stroke();
        ctx.beginPath(); ctx.moveTo(-this.radius, i); ctx.lineTo(this.radius, i); ctx.stroke();
    }
    ctx.restore();
    ctx.restore();
  }

  drawRareVisuals(ctx: CanvasRenderingContext2D) { 
    const t = Date.now() / 1000; 
    ctx.save(); 

    const corePulse = 0.5 + Math.sin(t * 12) * 0.1;
    const grad = ctx.createRadialGradient(0, 0, 0, 0, 0, this.radius * 0.8);
    grad.addColorStop(0, 'rgba(80, 239, 149, 0.8)');
    grad.addColorStop(1, 'rgba(80, 239, 149, 0)');
    ctx.fillStyle = grad;
    ctx.beginPath();
    ctx.arc(0, 0, this.radius * corePulse, 0, Math.PI * 2);
    ctx.fill();

    for(let i = 0; i < 5; i++) { 
        const orbitAngle = (t * (0.8 + i * 0.2)) + (i * Math.PI * 0.4); 
        const dist = this.radius * (1.6 + Math.sin(t * 2 + i) * 0.2); 
        const sx = Math.cos(orbitAngle) * dist;
        const sy = Math.sin(orbitAngle) * dist;

        ctx.save(); 
        ctx.translate(sx, sy); 
        ctx.rotate(orbitAngle + t * 4); 
        ctx.fillStyle = '#50ef95'; 
        ctx.shadowBlur = 15; ctx.shadowColor = '#50ef95'; 

        ctx.beginPath();
        ctx.moveTo(0, -6);
        ctx.lineTo(4, 0);
        ctx.lineTo(0, 6);
        ctx.lineTo(-4, 0);
        ctx.closePath();
        ctx.fill();
        ctx.restore(); 
    } 
    ctx.restore(); 
  }

  drawEpicVisuals(ctx: CanvasRenderingContext2D) { 
    const t = Date.now() / 900; 
    ctx.save(); 
    for (let j = 0; j < 3; j++) { 
        ctx.save();
        ctx.rotate((j % 2 === 0 ? t : -t * 1.5) + (j * Math.PI / 3));
        ctx.beginPath();
        ctx.arc(0, 0, this.radius * (1.3 + j * 0.4), 0, Math.PI * 2);
        ctx.strokeStyle = j === 0 ? 'rgba(255, 215, 0, 0.7)' : (j === 1 ? 'rgba(255, 160, 0, 0.5)' : 'rgba(255, 255, 255, 0.3)');
        ctx.lineWidth = 3;
        ctx.setLineDash([12 + j * 4, 10]);
        ctx.stroke();
        ctx.restore();
    }
    ctx.restore();
  }

  drawLegendaryVisuals(ctx: CanvasRenderingContext2D) { 
    const t = Date.now() / 400; 
    ctx.save(); 
    for(let i=0; i<6; i++) { 
        const s = 1.1 + (i * 0.2) + Math.sin(t*1.5 + i) * 0.15; 
        ctx.beginPath(); 
        this.traceShape(ctx, SHAPE_STATS[this.shapeType].sides, this.radius * s); 
        ctx.strokeStyle = `rgba(255, 90, 0, ${0.5 - i * 0.08})`; 
        ctx.lineWidth = 6; 
        ctx.stroke(); 
    } 
    ctx.restore(); 
  }

  drawMythicalVisuals(ctx: CanvasRenderingContext2D) { 
    const t = Date.now() / 1500; 
    ctx.save(); 
    const grad = ctx.createRadialGradient(0, 0, this.radius, 0, 0, this.radius * 2.5);
    grad.addColorStop(0, 'rgba(20, 0, 35, 0.9)');
    grad.addColorStop(1, 'rgba(162, 0, 255, 0)');
    ctx.fillStyle = grad;
    ctx.beginPath(); ctx.arc(0, 0, this.radius * 2.5, 0, Math.PI * 2); ctx.fill();
    ctx.restore(); 
  }

  drawEternalVisuals(ctx: CanvasRenderingContext2D) { 
    const t = Date.now() / 1000; 
    ctx.save(); 
    const grad = ctx.createRadialGradient(0, 0, this.radius * 0.5, 0, 0, this.radius * 4.5); 
    grad.addColorStop(0, 'rgba(0, 255, 255, 0.8)'); 
    grad.addColorStop(1, 'rgba(0, 255, 255, 0)'); 
    ctx.fillStyle = grad; 
    ctx.beginPath(); ctx.arc(0, 0, this.radius * 5, 0, Math.PI * 2); ctx.fill(); 
    ctx.restore(); 
  }
}

class Bullet extends Entity {
  ownerId: number;
  lifeTime: number = 0;
  maxLifeTime: number = 3000;
  isTrap: boolean = false;

  constructor(id: number, x: number, y: number, velocity: Vector2, owner: Tank, extraDamageMult: number = 1.0, extraLifeMult: number = 1.0, extraSizeMult: number = 1.0, isTrap: boolean = false) {
    const size = (6 + (owner.stats[StatType.BULLET_DAMAGE] * 0.3)) * extraSizeMult;
    const color = (owner.team === Team.BLUE) ? COLORS.player : (owner.team === Team.RED) ? COLORS.enemy : COLORS.barrel;
    super(id, EntityType.BULLET, x, y, size, color);
    this.team = owner.team;
    this.isTrap = isTrap;
    this.friction = isTrap ? 0.95 : 1.0; 
    this.vel = velocity;
    this.ownerId = owner.id;
    this.mass = size * 0.8; 
    this.damage = (BASE_STATS.bulletDamage + (owner.stats[StatType.BULLET_DAMAGE] * 3)) * extraDamageMult;
    const penetration = BASE_STATS.bulletPenetration + (owner.stats[StatType.BULLET_PENETRATION] * 5); 
    this.maxHealth = (10 + penetration * 3) * (isTrap ? 2.5 : 1.0) * extraDamageMult;
    this.health = this.maxHealth;
    this.displayHealth = this.maxHealth;
    this.maxLifeTime = (isTrap ? 8000 : 3000) * extraLifeMult;
  }

  override update(dt: number) { 
    super.update(dt); 
    this.lifeTime += dt * 1000; 
    if (this.lifeTime > this.maxLifeTime) this.isDead = true; 
  }

  override drawBody(ctx: CanvasRenderingContext2D) { 
    if (this.isTrap) {
        ctx.save();
        ctx.rotate(this.lifeTime * 0.005);
        ctx.beginPath();
        for(let i=0; i<3; i++) {
            const angle = (i * 2 * Math.PI) / 3;
            ctx.lineTo(Math.cos(angle) * this.radius, Math.sin(angle) * this.radius);
        }
        ctx.closePath();
        ctx.fillStyle = this.color;
        ctx.fill();
        ctx.lineWidth = 2;
        ctx.strokeStyle = COLORS.border;
        ctx.stroke();
        ctx.restore();
        return;
    }
    const remaining = this.maxLifeTime - this.lifeTime; 
    let alpha = remaining < 300 ? Math.max(0, remaining / 300) : 1.0; 
    ctx.globalAlpha = alpha; 
    super.drawBody(ctx); 
    ctx.globalAlpha = 1.0; 
  }
}

class SpatialGrid {
    cellSize: number;
    cells: Map<string, Entity[]> = new Map();
    width: number;
    height: number;

    constructor(cellSize: number, width: number, height: number) {
        this.cellSize = cellSize;
        this.width = width;
        this.height = height;
    }

    private getKey(x: number, y: number) {
        const cx = Math.floor(x / this.cellSize);
        const cy = Math.floor(y / this.cellSize);
        return `${cx},${cy}`;
    }

    clear() {
        this.cells.clear();
    }

    add(entity: Entity) {
        const key = this.getKey(entity.pos.x, entity.pos.y);
        if (!this.cells.has(key)) this.cells.set(key, []);
        this.cells.get(key)!.push(entity);
    }

    getNeighbors(entity: Entity): Entity[] {
        const cx = Math.floor(entity.pos.x / this.cellSize);
        const cy = Math.floor(entity.pos.y / this.cellSize);
        const neighbors: Entity[] = [];
        for (let x = cx - 1; x <= cx + 1; x++) {
            for (let y = cy - 1; y <= cy + 1; y++) {
                const key = `${x},${y}`;
                const cell = this.cells.get(key);
                if (cell) neighbors.push(...cell);
            }
        }
        return neighbors;
    }

    query(pos: Vector2, range: number): Entity[] {
        const startX = Math.floor((pos.x - range) / this.cellSize);
        const endX = Math.floor((pos.x + range) / this.cellSize);
        const startY = Math.floor((pos.y - range) / this.cellSize);
        const endY = Math.floor((pos.y + range) / this.cellSize);
        const results: Entity[] = [];

        for (let x = startX; x <= endX; x++) {
            for (let y = startY; y <= endY; y++) {
                const cell = this.cells.get(`${x},${y}`);
                if (cell) {
                    for (const e of cell) results.push(e);
                }
            }
        }
        return results;
    }
}

export class GameEngine {
  canvas: HTMLCanvasElement;
  ctx: CanvasRenderingContext2D;
  entities: Entity[] = [];
  particles: Particle[] = [];
  floatingTexts: FloatingText[] = [];
  uiNotifications: UINotification[] = [];
  player: Tank;
  width: number;
  height: number;
  keys: Set<string> = new Set();
  mouse: Vector2 = { x: 0, y: 0 };
  mouseDown: boolean = false;
  lastTime: number = 0;
  idCounter: number = 0;
  onStateUpdate: (state: GameState) => void;
  onGameOver: (score: number, level: number, classType: TankClass) => void;
  gameOverSignaled: boolean = false;
  sound: SoundEngine;
  darkMode: boolean = true; 
  gameMode: GameMode = GameMode.FFA;
  preferredTeam: Team = Team.BLUE;
  xp: number = 0;
  level: number = 1;
  maxShapes = 1000; 
  maxEnemies = 20;
  bossSpawnTimer: number = 0;
  killFeed: KillFeedEntry[] = [];
  attractMode: boolean = true;
  spectateTarget: Tank | null = null;
  cameraPos: Vector2 = { x: CANVAS_WIDTH/2, y: CANVAS_HEIGHT/2 };
  cameraZoom: number = 0.8;
  spatialGrid: SpatialGrid;
  lastUiUpdate: number = 0;

  inNest: boolean = false;
  crasherSpawnTimer: number = 0;
  bossDefenseTimer: number = 0;

  constructor(canvas: HTMLCanvasElement, onStateUpdate: (state: GameState) => void, onGameOver: (score: number, level: number, classType: TankClass) => void, gameMode: GameMode = GameMode.FFA) {
    this.canvas = canvas;
    this.ctx = canvas.getContext('2d')!;
    this.onStateUpdate = onStateUpdate;
    this.onGameOver = onGameOver;
    this.gameMode = gameMode;
    this.width = CANVAS_WIDTH;
    this.height = CANVAS_HEIGHT;
    this.sound = new SoundEngine();
    this.player = new Tank(this.nextId(), CANVAS_WIDTH / 2, CANVAS_HEIGHT / 2, true, Team.BLUE);
    this.entities.push(this.player);
    this.spatialGrid = new SpatialGrid(250, CANVAS_WIDTH, CANVAS_HEIGHT);
    for (let i = 0; i < 150; i++) this.spawnShape();
  }

  nextId() { return ++this.idCounter; }
  setPlayerName(name: string) { this.player.name = name; }
  setPlayerColor(color: string) { if (this.gameMode === GameMode.FFA) this.player.color = color; }
  setPlayerTeam(team: Team) { this.preferredTeam = team; }
  setGameMode(mode: GameMode) { this.gameMode = mode; }
  setDarkMode(enabled: boolean) { this.darkMode = enabled; }
  setAttractMode(enabled: boolean) { this.attractMode = enabled; }
  addNotification(text: string, color: string) { this.uiNotifications.push({ id: Math.random().toString(36), text, color, life: 2.5, maxLife: 2.5 }); }
  toggleAutoFire() { this.player.autoFire = !this.player.autoFire; this.addNotification(this.player.autoFire ? "AUTO FIRE ON" : "AUTO FIRE OFF", this.player.autoFire ? "#00e16e" : "#ff4444"); }
  toggleAutoSpin() { this.player.autoSpin = !this.player.autoSpin; this.addNotification(this.player.autoSpin ? "AUTO SPIN ON" : "AUTO SPIN OFF", this.player.autoSpin ? "#00e16e" : "#ff4444"); }
  spawnGuardians() { this.entities = this.entities.filter(e => e.type !== EntityType.GUARDIAN); const guardianCount = Math.floor(CANVAS_HEIGHT / 1200); for (let i = 1; i <= guardianCount; i++) { this.entities.push(new Guardian(this.nextId(), 300, i * (CANVAS_HEIGHT / (guardianCount + 1)), Team.BLUE)); this.entities.push(new Guardian(this.nextId(), CANVAS_WIDTH - 300, i * (CANVAS_HEIGHT / (guardianCount + 1)), Team.RED)); } }
  spawnBoss() { if (this.entities.find(e => e.type === EntityType.BOSS)) return; this.entities.push(new Boss(this.nextId())); this.addNotification("THE GRAND SINGULARITY HAS MANIFESTED!", "#00e16e"); this.sound.playLevelUp(); }
  resetPlayer(preserveWorld: boolean = false) {
    this.player.isDead = false; this.gameOverSignaled = false; 
    if (preserveWorld) { const newLevel = Math.max(1, Math.floor(this.level * 0.7)); this.level = newLevel; this.player.score = 0; this.xp = 0; this.player.availableStatPoints = Math.max(0, newLevel - 1); if (newLevel > 1) this.addNotification(`RESPAWNED AT LEVEL ${newLevel}`, "#33ccff"); }
    else { this.player.score = 0; this.level = 1; this.xp = 0; this.player.availableStatPoints = 0; }
    this.player.autoFire = false; this.player.autoSpin = false; this.uiNotifications = [];
    if (this.gameMode === GameMode.TEAMS) { this.player.team = this.preferredTeam; this.player.color = (this.preferredTeam === Team.BLUE) ? COLORS.player : COLORS.enemy; if (this.preferredTeam === Team.BLUE) this.player.pos = { x: Vector.randomRange(50, BASE_ZONE_WIDTH - 50), y: Vector.randomRange(50, CANVAS_HEIGHT - 50) }; else this.player.pos = { x: Vector.randomRange(CANVAS_WIDTH - BASE_ZONE_WIDTH + 50, CANVAS_WIDTH - 50), y: Vector.randomRange(50, CANVAS_HEIGHT - 50) }; }
    else { this.player.team = Team.BLUE; this.player.pos = Vector.randomPos(CANVAS_WIDTH, CANVAS_HEIGHT); }
    this.player.vel = { x: 0, y: 0 }; this.player.stats = { [StatType.REGEN]: 0, [StatType.MAX_HEALTH]: 0, [StatType.MAX_SHIELD]: 0, [StatType.BODY_DAMAGE]: 0, [StatType.BULLET_SPEED]: 0, [StatType.BULLET_PENETRATION]: 0, [StatType.BULLET_DAMAGE]: 0, [StatType.RELOAD]: 0, [StatType.MOVEMENT_SPEED]: 0, [StatType.BULLET_SPREAD]: 0 }; this.player.updateStats(); this.player.health = this.player.maxHealth; this.player.displayHealth = this.player.maxHealth; this.player.shield = 0; this.player.invulnerableTime = 3000; this.upgradeClass(TankClass.BASIC);
    if (!this.entities.includes(this.player)) this.entities.push(this.player);
    if (!preserveWorld) { this.entities = this.entities.filter(e => e.type === EntityType.SHAPE || e === this.player); this.killFeed = []; this.floatingTexts = []; this.particles = []; this.bossSpawnTimer = 0; if (this.gameMode === GameMode.TEAMS) this.spawnGuardians(); }
    if (this.gameMode !== GameMode.TEAMS) this.entities = this.entities.filter(e => e.type !== EntityType.GUARDIAN);
    this.attractMode = false;
  }

  start() { this.lastTime = performance.now(); this.loop(); }
  loop = () => { const now = performance.now(); const dt = Math.min((now - this.lastTime) / 1000, 0.1); this.lastTime = now; this.update(dt); this.draw(); requestAnimationFrame(this.loop); };
  handleInput(keys: Set<string>, mouse: Vector2, mouseDown: boolean) { this.keys = keys; this.mouse = mouse; this.mouseDown = mouseDown; }

  update(dt: number) {
    this.bossSpawnTimer += dt;
    if (this.bossSpawnTimer > 120) { this.spawnBoss(); this.bossSpawnTimer = 0; }

    this.crasherSpawnTimer += dt;
    if (this.crasherSpawnTimer > 5) {
        const nestRadius = 1500;
        const count = 3 + Math.floor(Math.random() * 3);
        for(let i=0; i<count; i++) {
            const angle = Math.random() * Math.PI * 2;
            const dist = Math.random() * nestRadius;
            this.entities.push(new Crasher(this.nextId(), CANVAS_WIDTH/2 + Math.cos(angle)*dist, CANVAS_HEIGHT/2 + Math.sin(angle)*dist));
        }
        this.crasherSpawnTimer = 0;
    }

    // Clear grid from previous frame and rebuild it with current positions for AI to use
    this.spatialGrid.clear();
    this.entities.forEach(e => this.spatialGrid.add(e));

    const currentBoss = this.entities.find(e => e.type === EntityType.BOSS) as Boss | undefined;
    if (currentBoss) {
        this.bossDefenseTimer += dt;
        if (this.bossDefenseTimer > 4) {
            const playersNearby = this.spatialGrid.query(currentBoss.pos, 1200).filter(e => e.type === EntityType.PLAYER || e.type === EntityType.ENEMY);
            if (playersNearby.length > 0) {
                const angle = Math.random() * Math.PI * 2;
                const spawnPos = Vector.add(currentBoss.pos, Vector.mult(Vector.fromAngle(angle), currentBoss.radius + 50));
                this.entities.push(new Crasher(this.nextId(), spawnPos.x, spawnPos.y, true));
            }
            this.bossDefenseTimer = 0;
        }
    }

    if (!this.attractMode) {
        const distToCenter = Vector.dist(this.player.pos, {x: CANVAS_WIDTH/2, y: CANVAS_HEIGHT/2});
        if (distToCenter < 1500 && !this.inNest) {
            this.inNest = true;
            this.addNotification("ENTERING THE PENTAGON NEST", "#768dfc");
        } else if (distToCenter >= 1500 && this.inNest) {
            this.inNest = false;
        }
    }

    if (this.attractMode) {
        if (!this.spectateTarget || this.spectateTarget.isDead || Math.random() < 0.005) {
            const bots = this.entities.filter(e => e.type === EntityType.ENEMY) as Tank[];
            this.spectateTarget = bots.length > 0 ? bots[Math.floor(Math.random() * bots.length)] : null;
        }
        let targetPos = this.spectateTarget ? this.spectateTarget.pos : {x: CANVAS_WIDTH/2, y: CANVAS_HEIGHT/2};
        this.cameraPos.x += (targetPos.x - this.cameraPos.x) * 0.05;
        this.cameraPos.y += (targetPos.y - this.cameraPos.y) * 0.05;
        this.cameraZoom = 0.6;
        this.player.pos = { x: -1000, y: -1000 };
    } else {
        this.cameraPos.x += (this.player.pos.x - this.cameraPos.x) * 0.1;
        this.cameraPos.y += (this.player.pos.y - this.cameraPos.y) * 0.1;
        this.cameraZoom = this.player.fov;
    }

    if (!this.attractMode && this.player.isDead && !this.gameOverSignaled) { this.gameOverSignaled = true; this.onGameOver(this.player.score, this.level, this.player.classType); }

    if (this.entities.filter(e => e.type === EntityType.SHAPE).length < this.maxShapes) {
      if (Math.random() < 0.35) this.spawnShape();
    }

    let enemyLimit = this.gameMode === GameMode.TEAMS ? 59 : 30;
    if (this.attractMode) enemyLimit += 10;
    if (this.entities.filter(e => e.type === EntityType.ENEMY).length < enemyLimit) { if(Math.random() < 0.05) this.spawnEnemy(); }

    if (!this.attractMode && !this.player.isDead) this.updatePlayerControl(dt);

    this.entities.forEach(e => {
        if (e.type === EntityType.ENEMY && !e.isDead) this.updateBotAI(e as Tank, dt);
        else if (e.type === EntityType.GUARDIAN) this.updateGuardianAI(e as Guardian, dt);
        else if (e.type === EntityType.CRASHER) this.updateCrasherAI(e as Crasher, dt);

        if (e.type === EntityType.SHAPE && (e as Shape).rarity !== ShapeRarity.COMMON) {
            if (Math.random() < 0.005) {
                const rarityColor = RARITY_CONFIG[(e as Shape).rarity].color || e.color;
                this.particles.push(new Particle(e.pos.x + Vector.randomRange(-e.radius, e.radius), e.pos.y + Vector.randomRange(-e.radius, e.radius), rarityColor, 2, 40));
            }
        }

        if (e.type === EntityType.BOSS) {
            if (Math.random() < 0.1) {
                this.particles.push(new Particle(e.pos.x + Vector.randomRange(-e.radius, e.radius), e.pos.y + Vector.randomRange(-e.radius, e.radius), '#00ffff', 4, 80));
            }
        }
    });

    if (this.gameMode === GameMode.TEAMS) {
        this.entities.forEach(e => {
            if (e.type === EntityType.PLAYER || e.type === EntityType.ENEMY) {
                if (e.team === Team.RED && e.pos.x < BASE_ZONE_WIDTH) e.vel.x += 1500 * dt;
                if (e.team === Team.BLUE && e.pos.x > CANVAS_WIDTH - BASE_ZONE_WIDTH) e.vel.x -= 1500 * dt;
            }
            if (e.type === EntityType.BULLET) {
                if (e.team === Team.RED && e.pos.x < BASE_ZONE_WIDTH) e.isDead = true;
                if (e.team === Team.BLUE && e.pos.x > CANVAS_WIDTH - BASE_ZONE_WIDTH) e.isDead = true;
            }
        });
    }

    this.entities.forEach(e => e.update(dt));

    // Rebuild grid after movement for collisions
    this.spatialGrid.clear();
    this.entities.forEach(e => this.spatialGrid.add(e));
    this.handleCollisions();

    this.particles.forEach(p => p.update());
    // Limit particles
    if (this.particles.length > 100) this.particles = this.particles.slice(this.particles.length - 100);
    this.particles = this.particles.filter(p => p.life > 0);

    this.floatingTexts.forEach(ft => ft.update());
    // Limit text
    if (this.floatingTexts.length > 50) this.floatingTexts = this.floatingTexts.slice(this.floatingTexts.length - 50);
    this.floatingTexts = this.floatingTexts.filter(ft => ft.life > 0);

    this.uiNotifications.forEach(n => n.life -= dt);
    this.uiNotifications = this.uiNotifications.filter(n => n.life > 0);
    this.entities = this.entities.filter(e => !e.isDead);
    this.killFeed = this.killFeed.filter(k => Date.now() - k.timestamp < 5000).slice(0, 6);

    const now = Date.now();
    // Throttle UI Updates (20 FPS cap for React state)
    if (now - this.lastUiUpdate > 50) {
        const leaderboard: LeaderboardEntry[] = (this.entities.filter(e => (e.type === EntityType.PLAYER || e.type === EntityType.ENEMY) && !e.isDead) as Tank[])
            .sort((a, b) => b.score - a.score).slice(0, 10).map(e => ({ id: e.id, name: e.name || 'Unknown', score: e.score, classType: e.classType, isPlayer: e.id === this.player.id, team: e.team }));

        this.onStateUpdate({ score: this.player.score, level: this.level, xp: this.xp, maxXp: this.getLevelXp(this.level), stats: this.player.stats, availableStatPoints: this.player.availableStatPoints, currentClass: this.player.classType, isDead: this.player.isDead, fps: Math.round(1/dt), killFeed: this.killFeed, leaderboard: leaderboard, notifications: this.uiNotifications, health: this.player.displayHealth, maxHealth: this.player.maxHealth, shield: this.player.shield, maxShield: this.player.maxShield, playerPos: this.player.pos, playerRotation: this.player.rotation, camera: { x: this.cameraPos.x, y: this.cameraPos.y, zoom: this.cameraZoom }, mapSize: { width: CANVAS_WIDTH, height: CANVAS_HEIGHT }, gameMode: this.gameMode, autoFire: this.player.autoFire, autoSpin: this.player.autoSpin });
        this.lastUiUpdate = now;
    }
  }

  private isOnScreen(pos: Vector2, radius: number = 50): boolean {
    const margin = radius + 200;
    const viewW = window.innerWidth / this.cameraZoom;
    const viewH = window.innerHeight / this.cameraZoom;
    return (
        pos.x >= this.cameraPos.x - viewW/2 - margin &&
        pos.x <= this.cameraPos.x + viewW/2 + margin &&
        pos.y >= this.cameraPos.y - viewH/2 - margin &&
        pos.y <= this.cameraPos.y + viewH/2 + margin
    );
  }

  updateCrasherAI(crasher: Crasher, dt: number) {
      const vision = crasher.isAlphaCrasher ? 1200 : 800;
      let target: Entity | null = null;
      // Optimize: Only check nearby entities
      const nearby = this.spatialGrid.query(crasher.pos, vision);
      let minDist = vision;

      for(const e of nearby) {
          if (e.isDead) continue;
          if (e.type !== EntityType.PLAYER && e.type !== EntityType.ENEMY) continue;
          const d = Vector.dist(crasher.pos, e.pos);
          if (d < minDist) { minDist = d; target = e; }
      }
      if (target) {
          const dir = Vector.normalize(Vector.sub(target.pos, crasher.pos));
          const speed = BASE_STATS.speed * (crasher.isAlphaCrasher ? 1.4 : 1.125);
          crasher.acc = Vector.mult(dir, speed * dt * 60);
      } else { if (Math.random() < 0.01) crasher.acc = Vector.mult(Vector.fromAngle(Math.random()*Math.PI*2), 2); }
  }

  updateGuardianAI(guardian: Guardian, dt: number) {
      const vision = 1000;
      let target: Entity | null = null;
      let minDist = vision;
      const nearby = this.spatialGrid.query(guardian.pos, vision);

      for (const e of nearby) {
          if (e.isDead) continue;
          if (e.type !== EntityType.PLAYER && e.type !== EntityType.ENEMY && e.type !== EntityType.BULLET) continue;
          if (e.team === guardian.team || e.team === Team.NONE) continue;
          const d = Vector.dist(guardian.pos, e.pos);
          if (d < minDist) { minDist = d; target = e; }
      }
      if (target) {
          const dir = Vector.normalize(Vector.sub(target.pos, guardian.pos));
          guardian.acc = Vector.mult(dir, 800 * dt);
      } else {
          guardian.orbitAngle += dt * 0.5;
          const orbitRadius = 150;
          const targetPos = {
              x: guardian.homePos.x + Math.cos(guardian.orbitAngle) * orbitRadius,
              y: guardian.homePos.y + Math.sin(guardian.orbitAngle) * orbitRadius
          };
          const dir = Vector.normalize(Vector.sub(targetPos, guardian.pos));
          guardian.acc = Vector.mult(dir, 400 * dt);
      }
  }

  updatePlayerControl(dt: number) {
    const moveDir = { x: 0, y: 0 };
    if (this.keys.has('w') || this.keys.has('ArrowUp')) moveDir.y -= 1;
    if (this.keys.has('s') || this.keys.has('ArrowDown')) moveDir.y += 1;
    if (this.keys.has('a') || this.keys.has('ArrowLeft')) moveDir.x -= 1;
    if (this.keys.has('d') || this.keys.has('ArrowRight')) moveDir.x += 1;
    this.applyTankMovement(this.player, moveDir);

    if (this.player.autoSpin) {
        this.player.rotation += 1.5 * dt;
    } else {
        const mouseOffset = Vector.sub(this.mouse, { x: window.innerWidth / 2, y: window.innerHeight / 2 });
        const targetPos = Vector.add(this.player.pos, Vector.div(mouseOffset, this.player.fov));
        const aimDir = Vector.sub(targetPos, this.player.pos);
        const targetRot = Math.atan2(aimDir.y, aimDir.x);

        let diff = targetRot - this.player.rotation;
        while (diff > Math.PI) diff -= Math.PI * 2;
        while (diff < -Math.PI) diff += Math.PI * 2;
        this.player.rotation += diff * 0.25; 
    }

    if (this.mouseDown || this.player.autoFire) this.attemptShoot(this.player);
  }

  updateBotAI(bot: Tank, dt: number) {
      // AI Throttling
      if (Date.now() < bot.nextAiUpdate) {
          // Continue with cached intent
          if (Vector.mag(bot.aiMoveDir) > 0) this.applyTankMovement(bot, bot.aiMoveDir);

          let diff = bot.aiTargetRot - bot.rotation;
          while (diff > Math.PI) diff -= Math.PI * 2; while (diff < -Math.PI) diff += Math.PI * 2;
          const turnSpeed = (bot.classType === TankClass.SNIPER || bot.classType === TankClass.ASSASSIN ? 0.05 : 0.15);
          if (Math.abs(diff) < turnSpeed) bot.rotation = bot.aiTargetRot; else bot.rotation += Math.sign(diff) * turnSpeed;

          if (bot.aiShooting && Math.abs(diff) < 0.3) this.attemptShoot(bot);
          return;
      }

      // Update timer (staggered)
      bot.nextAiUpdate = Date.now() + 100 + Math.random() * 100;

      const visionRadius = bot.visionRange;
      const visibleEntities = this.spatialGrid.query(bot.pos, visionRadius);

      const enemies = visibleEntities.filter(e => e.id !== bot.id && (e.type === EntityType.PLAYER || e.type === EntityType.ENEMY) && (this.gameMode === GameMode.FFA || e.team !== bot.team));
      const shapes = visibleEntities.filter(e => e.type === EntityType.SHAPE || e.type === EntityType.BOSS || e.type === EntityType.CRASHER);
      const threats = visibleEntities.filter(e => e.type === EntityType.BULLET && (e as Bullet).ownerId !== bot.id && e.team !== bot.team) as Bullet[];
      const nearestEnemy = this.findNearest(bot, enemies) as Tank | null;
      const nearestShape = this.findNearest(bot, shapes);

      let optimalRange = 350; let kiteDistance = 250;
      if (bot.classType === TankClass.SNIPER || bot.classType === TankClass.ASSASSIN || bot.classType === TankClass.RANGER || bot.classType === TankClass.HUNTER) { optimalRange = 600; kiteDistance = 500; }
      else if (bot.classType === TankClass.MACHINE_GUN || bot.classType === TankClass.DESTROYER || bot.classType === TankClass.SPRAYER || bot.classType === TankClass.GUNNER) { optimalRange = 250; kiteDistance = 100; }
      else if (bot.classType === TankClass.SMASHER || bot.classType === TankClass.MEGA_SMASHER || bot.classType === TankClass.LANDMINE) { optimalRange = 0; kiteDistance = 0; }

      let target: Entity | null = null;
      let shouldShoot = false;
      bot.aiState = 'IDLE';

      if (bot.health < bot.maxHealth * 0.3 && nearestEnemy) bot.aiState = 'FLEE';
      else if (nearestEnemy) { bot.aiState = 'COMBAT'; target = nearestEnemy; shouldShoot = true; }
      else if (nearestShape) { bot.aiState = 'FARM'; target = nearestShape; shouldShoot = true; }

      let moveForce = { x: 0, y: 0 };
      if (bot.aiState === 'FLEE' && nearestEnemy) { moveForce = Vector.add(moveForce, Vector.mult(Vector.normalize(Vector.sub(bot.pos, nearestEnemy.pos)), 3.0)); if (this.gameMode === GameMode.TEAMS) moveForce = Vector.add(moveForce, Vector.mult(bot.team === Team.BLUE ? {x:-1,y:0} : {x:1,y:0}, 1.5)); }
      else if (bot.aiState === 'COMBAT' && target) { 
          const dist = Vector.dist(bot.pos, target.pos); 
          const dir = Vector.sub(target.pos, bot.pos); 
          if (dist > optimalRange) moveForce = Vector.add(moveForce, Vector.mult(Vector.normalize(dir), 1.0)); 
          else if (dist < kiteDistance) moveForce = Vector.add(moveForce, Vector.mult(Vector.normalize(dir), -1.2)); 
          else moveForce = Vector.add(moveForce, Vector.mult(Vector.normalize({ x: -dir.y, y: dir.x }), 0.8 * (bot.id % 2 === 0 ? 1 : -1))); 
      }
      else if (bot.aiState === 'FARM' && target) { 
          const dir = Vector.sub(target.pos, bot.pos); 
          const dist = Vector.dist(bot.pos, target.pos); 
          if (dist > 150) moveForce = Vector.add(moveForce, Vector.mult(Vector.normalize(dir), 0.8)); 
          else if (dist < 100) moveForce = Vector.add(moveForce, Vector.mult(Vector.normalize(dir), -0.5)); 
      }
      else if (Math.random() < 0.05) bot.acc = Vector.add(bot.acc, Vector.mult(Vector.fromAngle(Math.random()*Math.PI*2), 5));

      for (const bullet of threats) { if (Vector.dist(bot.pos, bullet.pos) < 250) { const toBot = Vector.sub(bot.pos, bullet.pos); if (Vector.dot(Vector.normalize(bullet.vel), Vector.normalize(toBot)) > 0.9) moveForce = Vector.add(moveForce, Vector.mult(Vector.normalize({ x: -bullet.vel.y, y: bullet.vel.x }), (bullet.vel.x * toBot.y - bullet.vel.y * toBot.x) > 0 ? 4.0 : -4.0)); } }
      for (const shape of shapes) { 
          if (Vector.dist(bot.pos, shape.pos) < bot.radius + shape.radius + 30) {
              if (bot.aiState !== 'FARM' || bot.classType === TankClass.SMASHER) moveForce = Vector.add(moveForce, Vector.mult(Vector.normalize(Vector.sub(bot.pos, shape.pos)), 2.5)); 
          }
      }

      if (bot.pos.x < 100) moveForce.x += 5; if (bot.pos.x > CANVAS_WIDTH - 100) moveForce.x -= 5; if (bot.pos.y < 100) moveForce.y += 5; if (bot.pos.y > CANVAS_HEIGHT - 100) moveForce.y -= 5;
      if (this.gameMode === GameMode.TEAMS) { if (bot.team === Team.RED && bot.pos.x < BASE_ZONE_WIDTH+100) moveForce.x += 5; if (bot.team === Team.BLUE && bot.pos.x > CANVAS_WIDTH - (BASE_ZONE_WIDTH+100)) moveForce.x -= 5; }

      // Cache intent
      bot.aiMoveDir = moveForce;
      bot.aiShooting = shouldShoot;

      if (Vector.mag(moveForce) > 0) this.applyTankMovement(bot, moveForce);

      if (target) {
          let aimPoint = target.pos;
          const dist = Vector.dist(bot.pos, target.pos);
          let botBulletSpeedMult = 1.0;
          if (bot.classType === TankClass.SNIPER || bot.classType === TankClass.HUNTER) botBulletSpeedMult = 1.15;
          else if (bot.classType === TankClass.ASSASSIN) botBulletSpeedMult = 1.35;
          const bulletSpeed = (BASE_STATS.bulletSpeed + bot.stats[StatType.BULLET_SPEED]) * botBulletSpeedMult;
          if (target.vel) aimPoint = Vector.add(target.pos, Vector.mult(target.vel, (dist / (bulletSpeed * 60)) * 30));
          const targetRot = Math.atan2(Vector.sub(aimPoint, bot.pos).y, Vector.sub(aimPoint, bot.pos).x);

          bot.aiTargetRot = targetRot;

          let diff = targetRot - bot.rotation;
          while (diff > Math.PI) diff -= Math.PI * 2; while (diff < -Math.PI) diff += Math.PI * 2;
          const turnSpeed = (bot.classType === TankClass.SNIPER || bot.classType === TankClass.ASSASSIN ? 0.05 : 0.15);
          if (Math.abs(diff) < turnSpeed) bot.rotation = targetRot; else bot.rotation += Math.sign(diff) * turnSpeed;
          if (shouldShoot && Math.abs(diff) < 0.3) this.attemptShoot(bot);
      }

      if (bot.availableStatPoints > 0) { const priorities = BOT_STAT_PRIORITIES[bot.classType] || Object.values(StatType); this.upgradeStat(bot, priorities[Math.floor(Math.random() * (priorities.length / 2))]); }
  }

  awardXP(tank: Tank, amount: number) {
      tank.score += amount;
      if (tank === this.player) {
          this.xp += amount;
          while (this.level < MAX_LEVEL && this.xp >= this.getLevelXp(this.level)) {
              this.xp -= this.getLevelXp(this.level);
              this.level++;
              this.player.availableStatPoints++;
              this.sound.playLevelUp();
          }
      } else if (Math.random() < 0.5 && tank.availableStatPoints < 30) {
          tank.availableStatPoints++;
      }
  }

  attemptShoot(tank: Tank) {
    if (tank.classType === TankClass.SMASHER || tank.classType === TankClass.MEGA_SMASHER || tank.classType === TankClass.LANDMINE) return;

    const baseReloadTimeMs = (BASE_STATS.reload - (tank.stats[StatType.RELOAD] * 2.5)) * 16; 
    let shotFired = false;
    let bulletSpeedMult = 1.0, bulletDamageMult = 1.0, bulletLifeMult = 1.0, bulletSizeMult = 1.0;
    let isTrapClass = tank.classType === TankClass.TRAPPER || tank.classType === TankClass.TRI_TRAPPER || tank.classType === TankClass.GUNNER_TRAPPER || tank.classType === TankClass.MEGA_TRAPPER;

    // Balance Pass
    if (tank.classType === TankClass.SNIPER) { bulletSpeedMult = 1.15; bulletDamageMult = 1.35; bulletLifeMult = 1.25; }
    else if (tank.classType === TankClass.ASSASSIN || tank.classType === TankClass.STALKER) { bulletSpeedMult = 1.35; bulletDamageMult = 1.55; bulletLifeMult = 1.6; }
    else if (tank.classType === TankClass.RANGER) { bulletSpeedMult = 1.65; bulletDamageMult = 1.95; bulletLifeMult = 2.0; }
    else if (tank.classType === TankClass.DESTROYER || tank.classType === TankClass.HYBRID) { bulletSizeMult = 3.6; bulletDamageMult = 5.5; bulletLifeMult = 1.5; bulletSpeedMult = 0.85; }
    else if (tank.classType === TankClass.ANNIHILATOR) { bulletSizeMult = 4.5; bulletDamageMult = 6.5; bulletLifeMult = 1.6; bulletSpeedMult = 0.8; }
    else if (tank.classType === TankClass.SPRAYER) { bulletDamageMult = 0.85; bulletSpeedMult = 1.15; }
    else if (tank.classType === TankClass.GUNNER || tank.classType === TankClass.AUTO_5 || tank.classType === TankClass.AUTO_3) { bulletSizeMult = 0.65; bulletDamageMult = 0.7; bulletSpeedMult = 1.65; }
    else if (tank.classType === TankClass.OVERLORD || tank.classType === TankClass.OVERSEER) { bulletSizeMult = 1.4; bulletDamageMult = 2.0; bulletLifeMult = 5.0; bulletSpeedMult = 0.75; }
    else if (tank.classType === TankClass.MEGA_TRAPPER) { bulletSizeMult = 2.5; bulletDamageMult = 3.0; }

    tank.barrels.forEach((barrel, index) => {
         if (tank.barrelCooldowns[index] > 0) return;
         const [length, width, xOff, angleOff, delayMultiplier, yOff = 0] = barrel;
         let extraDmg = 1.0;
         let extraSize = 1.0;
         let isTrap = isTrapClass;

         // Custom Gunner Trapper logic: Front barrels are bullets, rear is trap
         if (tank.classType === TankClass.GUNNER_TRAPPER) {
             if (index < 2) { isTrap = false; extraDmg = 0.6; extraSize = 0.6; }
             else { isTrap = true; extraDmg = 1.2; extraSize = 1.1; }
         }

         const cooldownVal = Math.max(40, baseReloadTimeMs * delayMultiplier);
         tank.barrelCooldowns[index] = cooldownVal;
         tank.barrelMaxCooldowns[index] = cooldownVal;

         const accuracyFactor = Math.pow(0.82, tank.stats[StatType.BULLET_SPREAD]); 
         const angle = tank.rotation + angleOff + Vector.randomRange(-tank.spread * accuracyFactor, tank.spread * accuracyFactor);
         const forward = { x: Math.cos(angle), y: Math.sin(angle) };
         const lateralAngle = tank.rotation + Math.PI/2;
         const startPos = Vector.add(tank.pos, { x: Math.cos(lateralAngle) * (yOff * tank.radius), y: Math.sin(lateralAngle) * (yOff * tank.radius) });
         const tip = Vector.add(startPos, Vector.mult(forward, tank.radius * length));

         const bulletVelocity = Vector.mult(forward, (BASE_STATS.bulletSpeed + tank.stats[StatType.BULLET_SPEED] * 0.8) * bulletSpeedMult * (isTrap ? 0.5 : 1.0));
         this.entities.push(new Bullet(this.nextId(), tip.x, tip.y, bulletVelocity, tank, bulletDamageMult * extraDmg, bulletLifeMult, bulletSizeMult * extraSize, isTrap));

         let recoilPower = 0.5;
         if (tank.classType === TankClass.DESTROYER || tank.classType === TankClass.HYBRID) recoilPower = 12.0;
         else if (tank.classType === TankClass.ANNIHILATOR) recoilPower = 16.0;
         else if (tank.classType === TankClass.TRI_ANGLE || tank.classType === TankClass.FIGHTER) recoilPower = (angleOff === 0) ? 0.4 : 1.8;
         else if (tank.classType === TankClass.BOOSTER) recoilPower = (angleOff === 0) ? 0.4 : 2.2;

         tank.vel = Vector.sub(tank.vel, Vector.mult(forward, recoilPower)); 
         tank.visualScale = 0.85; 
         shotFired = true;
    });
    if (shotFired) { if (tank === this.player || this.isOnScreen(tank.pos)) { this.sound.playShoot(tank.classType); } }
  }

  applyTankMovement(tank: Tank, dir: Vector2) { if (Vector.mag(dir) > 0) tank.acc = Vector.mult(Vector.normalize(dir), (BASE_STATS.speed + tank.stats[StatType.MOVEMENT_SPEED] * 0.7) * (1 - tank.friction) / tank.friction); }
  findNearest(origin: Entity, targets: Entity[]): Entity | null { let nearest = null; let minDst = Infinity; for (const t of targets) { const d = Vector.dist(origin.pos, t.pos); if (d < minDst) { minDst = d; nearest = t; } } return nearest; }

  spawnEnemy() {
      let pos = Vector.randomPos(CANVAS_WIDTH, CANVAS_HEIGHT);
      let team = Team.RED;
      if (this.gameMode === GameMode.TEAMS) {
          const blueTanks = this.entities.filter(e => (e.type === EntityType.PLAYER || e.type === EntityType.ENEMY) && e.team === Team.BLUE).length;
          const redTanks = this.entities.filter(e => (e.type === EntityType.PLAYER || e.type === EntityType.ENEMY) && e.team === Team.RED).length;
          if (blueTanks < 30 && redTanks < 30) team = Math.random() < 0.5 ? Team.BLUE : Team.RED;
          else if (blueTanks < 30) team = Team.BLUE; else if (redTanks < 30) team = Team.RED; else return;
          pos.x = team === Team.BLUE ? Vector.randomRange(50, CANVAS_WIDTH / 2) : Vector.randomRange(CANVAS_WIDTH / 2, CANVAS_WIDTH - 50);
      }
      const bot = new Tank(this.nextId(), pos.x, pos.y, false, team);
      bot.name = BOT_NAMES[Math.floor(Math.random() * BOT_NAMES.length)];
      const targetLevel = Math.floor(Math.random() * 35) + 10; 
      const classes = Object.values(TankClass);
      const chosenClass = classes[Math.floor(Math.random() * classes.length)];
      this.upgradeClassForTank(bot, chosenClass);
      let pointsToSpend = targetLevel - 1; const priorities = BOT_STAT_PRIORITIES[chosenClass] || BOT_STAT_PRIORITIES[TankClass.BASIC];
      while (pointsToSpend > 0) { for (const stat of priorities) { if (pointsToSpend <= 0) break; if (bot.stats[stat] < 8) { bot.stats[stat]++; pointsToSpend--; } } }
      bot.updateStats(); bot.health = bot.maxHealth; bot.score = 500 * targetLevel; 
      this.entities.push(bot);
  }

  spawnShape() {
    const center = { x: CANVAS_WIDTH / 2, y: CANVAS_HEIGHT / 2 };
    const nestRadius = 1500;
    const isNestSpawn = Math.random() < 0.2; 
    let pos: Vector2; let type: ShapeType;
    if (isNestSpawn) {
        const angle = Math.random() * Math.PI * 2;
        const dist = Math.sqrt(Math.random()) * nestRadius;
        pos = { x: center.x + Math.cos(angle) * dist, y: center.y + Math.sin(angle) * dist };
        const roll = Math.random();
        if (roll < 0.1) type = ShapeType.OCTAGON;
        else if (roll < 0.3) type = ShapeType.HEXAGON;
        else if (roll < 0.7) type = ShapeType.PENTAGON;
        else type = ShapeType.TRIANGLE;
    } else {
        pos = Vector.randomPos(CANVAS_WIDTH, CANVAS_HEIGHT);
        const roll = Math.random();
        if (roll < 0.02) type = ShapeType.OCTAGON;
        else if (roll < 0.05) type = ShapeType.HEXAGON;
        else if (roll < 0.15) type = ShapeType.PENTAGON;
        else if (roll < 0.45) type = ShapeType.TRIANGLE;
        else type = ShapeType.SQUARE;
    }
    if (Vector.dist(pos, this.player.pos) < 250) return;
    this.entities.push(new Shape(this.nextId(), pos.x, pos.y, type));
  }

  handleCollisions() {
    // Entities are already in the grid from the main update loop
    // Only query neighbours for active entities
    this.entities.forEach(a => {
        if (a.isDead) return;
        const neighbors = this.spatialGrid.getNeighbors(a);
        neighbors.forEach(b => {
            if (a === b || b.isDead) return;
            // Basic distance check (fast)
            const minDist = a.radius + b.radius;
            // Optimization: Skip sqrt
            const d2 = (a.pos.x - b.pos.x) ** 2 + (a.pos.y - b.pos.y) ** 2;

            if (d2 < minDist * minDist) {
                if (this.gameMode === GameMode.TEAMS && a.team === b.team && a.team !== Team.NONE) {
                    if (a.type !== EntityType.BULLET && b.type !== EntityType.BULLET) {
                        this.resolveCollision(a, b, false);
                    }
                    return;
                }
                if (a.type === EntityType.BULLET && (a as Bullet).ownerId === b.id) return;
                if (b.type === EntityType.BULLET && (b as Bullet).ownerId === a.id) return;
                this.resolveCollision(a, b, true);
            }
        });
    });
  }

  resolveCollision(a: Entity, b: Entity, applyDamage: boolean = true) {
     const dir = Vector.normalize(Vector.sub(a.pos, b.pos));
     const distVal = Vector.dist(a.pos, b.pos);
     const overlap = (a.radius + b.radius) - distVal;

     let ratioA = 0.5, ratioB = 0.5;
     let positionalCorrectionFactor = 1.0; 
     if (a.type === EntityType.BULLET || b.type === EntityType.BULLET) positionalCorrectionFactor = 0.05; 

     if (a.type === EntityType.BOSS || b.type === EntityType.BOSS) { if (a.type === EntityType.BOSS) { ratioA = 0.0; ratioB = 1.0; } else { ratioA = 1.0; ratioB = 0.0; } }
     else if (a.type === EntityType.GUARDIAN || b.type === EntityType.GUARDIAN) { if (a.type === EntityType.GUARDIAN && b.type !== EntityType.GUARDIAN) { ratioA = 0.05; ratioB = 1.0; } else if (b.type === EntityType.GUARDIAN && a.type !== EntityType.GUARDIAN) { ratioA = 1.0; ratioB = 0.05; } }
     else if (a.type === EntityType.BULLET && b.type !== EntityType.BULLET) { ratioA = 0.01; ratioB = 0.99; }
     else if (b.type === EntityType.BULLET && a.type !== EntityType.BULLET) { ratioA = 0.99; ratioB = 0.01; }
     else { const totalMass = a.mass + b.mass; ratioA = b.mass / totalMass; ratioB = a.mass / totalMass; }

     const force = Vector.mult(dir, overlap * positionalCorrectionFactor);
     a.pos = Vector.add(a.pos, Vector.mult(force, ratioA));
     b.pos = Vector.sub(b.pos, Vector.mult(force, ratioB));

     if (!applyDamage) return;
     let dmgToA = b.damage, dmgToB = a.damage;
     let sourceIdForA: number | null = null, sourceIdForB: number | null = null;
     if (b.type === EntityType.BULLET) sourceIdForA = (b as Bullet).ownerId; else if (b.type === EntityType.PLAYER || b.type === EntityType.ENEMY) sourceIdForA = b.id;
     if (a.type === EntityType.BULLET) sourceIdForB = (a as Bullet).ownerId; else if (a.type === EntityType.PLAYER || a.type === EntityType.ENEMY) sourceIdForB = a.id;

     if (a.type === EntityType.SHAPE && b.type === EntityType.SHAPE) { dmgToA = 0; dmgToB = 0; }
     if ((a.type === EntityType.PLAYER || a.type === EntityType.ENEMY) && b.type === EntityType.SHAPE) dmgToA *= 0.2; 
     else if ((b.type === EntityType.PLAYER || b.type === EntityType.ENEMY) && a.type === EntityType.SHAPE) dmgToB *= 0.2;

     if (a.type === EntityType.PLAYER && b.type === EntityType.BULLET) dmgToA *= 0.5; else if (b.type === EntityType.PLAYER && a.type === EntityType.BULLET) dmgToB *= 0.5;

     a.takeDamage(dmgToA, sourceIdForA); b.takeDamage(dmgToB, sourceIdForB);
     if (dmgToA > 1 && a.type !== EntityType.GUARDIAN && a.type !== EntityType.BULLET) this.spawnDamageText(a.pos, dmgToA, a.id);
     if (dmgToB > 1 && b.type !== EntityType.GUARDIAN && b.type !== EntityType.BULLET) this.spawnDamageText(b.pos, dmgToB, b.id);

     if (a.type === EntityType.BULLET || b.type === EntityType.BULLET) {
       const isPlayerInvolved = (a.type === EntityType.PLAYER || b.type === EntityType.PLAYER) || (a.type === EntityType.BULLET && (a as Bullet).ownerId === this.player.id) || (b.type === EntityType.BULLET && (b as Bullet).ownerId === this.player.id);
       if (isPlayerInvolved || this.isOnScreen(a.pos)) { this.sound.playHit(); }
     }

     const baseKnockback = 2.0;
     if (a.type === EntityType.BULLET && b.type !== EntityType.BULLET) {
         let knockbackMult = (a as Bullet).isTrap ? 0.2 : 1.0;
         const massMult = Math.min(1.0, 35 / b.mass); 
         b.vel = Vector.add(b.vel, Vector.mult(dir, -(baseKnockback * massMult * knockbackMult))); 
     } else if (b.type === EntityType.BULLET && a.type !== EntityType.BULLET) {
         let knockbackMult = (b as Bullet).isTrap ? 0.2 : 1.0;
         const massMult = Math.min(1.0, 35 / a.mass);
         a.vel = Vector.add(a.vel, Vector.mult(dir, baseKnockback * massMult * knockbackMult));
     }
     if (a.isDead) this.handleDeath(a, b); if (b.isDead) this.handleDeath(b, a);
  }

  spawnDamageText(pos: Vector2, amount: number, entityId: number | null = null) { const val = Math.floor(amount); if (val === 0) return; if (entityId !== null) { const existing = this.floatingTexts.find(ft => ft.type === 'DAMAGE' && ft.entityId === entityId); if (existing) { existing.stack(val); existing.pos.x = pos.x; existing.pos.y = pos.y - 25; return; } } this.floatingTexts.push(new FloatingText(pos.x, pos.y - 20, val, 'DAMAGE', val > 20 ? 26 : 18, val > 20, entityId)); }
  spawnScoreText(pos: Vector2, amount: number) { this.floatingTexts.push(new FloatingText(pos.x, pos.y - 25, amount, 'SCORE', 22)); }
  spawnParticles(pos: Vector2, color: string, count: number, size: number = 3) {
      for(let i=0; i<count; i++) this.particles.push(new Particle(pos.x, pos.y, color, size + Math.random() * 2));
  }

  handleDeath(victim: Entity, killer: Entity) {
      if (this.isOnScreen(victim.pos)) { 
        this.sound.playExplosion(victim.radius > 20); 
        this.spawnParticles(victim.pos, victim.color, victim.radius > 20 ? 12 : 6, victim.radius / 5);
      }
      if (victim.type === EntityType.PLAYER || victim.type === EntityType.ENEMY || victim.type === EntityType.BOSS) {
            let killerName = killer.name;
            if (killer.type === EntityType.BULLET) { const owner = this.entities.find(e => e.id === (killer as Bullet).ownerId); killerName = owner ? owner.name : "Unknown"; }
            else if (killer.type === EntityType.SHAPE) killerName = (killer as Shape).shapeType; 
            else if (killer.type === EntityType.GUARDIAN) killerName = "Base Guardian";
            else if (killer.type === EntityType.BOSS) killerName = "Grand Singularity";
            else if (killer.type === EntityType.CRASHER) killerName = (killer as Crasher).isAlphaCrasher ? "Alpha Crasher" : "Crasher";
            this.addToKillFeed(killerName || 'Unknown', victim.name || 'Unknown');
      }
      if (victim.type === EntityType.BOSS) this.addNotification("THE GRAND SINGULARITY HAS BEEN DEFEATED!", "#00e16e");
      if (victim.type === EntityType.SHAPE || victim.type === EntityType.BOSS) {
          const v = victim as (Shape | Boss);
          const totalXp = victim.type === EntityType.SHAPE ? (v as Shape).xpValue : (v as Boss).xpValue;
          let totalDmg = 0; v.damageDealtBy.forEach(val => totalDmg += val);
          if (totalDmg > 0) {
              v.damageDealtBy.forEach((dmg, id) => {
                  const tank = this.entities.find(e => e.id === id) as Tank | undefined;
                  if (tank && (tank.type === EntityType.PLAYER || tank.type === EntityType.ENEMY)) {
                      const share = Math.floor(totalXp * (dmg / totalDmg));
                      if (share > 0) {
                          this.awardXP(tank, share);
                          if (tank === this.player || Vector.dist(victim.pos, this.player.pos) < 800) this.spawnScoreText(victim.pos, share);
                      }
                  }
              });
              return; 
          }
      }
      let killerTank: Tank | null = null;
      if (killer.type === EntityType.PLAYER || killer.type === EntityType.ENEMY) killerTank = killer as Tank;
      else if (killer.type === EntityType.BULLET) { const owner = this.entities.find(e => e.id === (killer as Bullet).ownerId); if (owner && (owner.type === EntityType.PLAYER || owner.type === EntityType.ENEMY)) killerTank = owner as Tank; }
      if (killerTank) {
          let xp = 10; if (victim.type === EntityType.ENEMY || victim.type === EntityType.PLAYER) xp = (victim as Tank).score > 0 ? (victim as Tank).score / 2 : 500;
          this.awardXP(killerTank, xp);
          if (killerTank === this.player || Vector.dist(victim.pos, this.player.pos) < 800) this.spawnScoreText(victim.pos, xp);
      }
  }

  addToKillFeed(killerName: string, victimName: string) { 
      this.killFeed.unshift({ id: `${Date.now()}-${Math.random()}`, killerName, victimName, timestamp: Date.now() }); 
      if (this.killFeed.length > 6) this.killFeed.pop();
  }

  getLevelXp(level: number) { return Math.floor(100 * Math.pow(XP_CURVE_MULTIPLIER, level - 1)); }
  upgradeStat(tank: Tank, stat: StatType) { if (tank.availableStatPoints > 0 && tank.stats[stat] < 8) { tank.stats[stat]++; tank.availableStatPoints--; tank.updateStats(); if (tank.id === this.player.id) this.sound.playStatUpgrade(); } }
  upgradeClass(newClass: TankClass) { this.upgradeClassForTank(this.player, newClass); this.sound.playClassUpgrade(); }
  upgradeClassForTank(tank: Tank, newClass: TankClass) {
      tank.classType = newClass; tank.barrels = TANK_CONFIGS[newClass];

      // Class Specific Logic
      if (newClass === TankClass.SNIPER || newClass === TankClass.ASSASSIN || newClass === TankClass.RANGER || newClass === TankClass.HUNTER || newClass === TankClass.PREDATOR || newClass === TankClass.STALKER || newClass === TankClass.STREAMLINER) { 
          tank.fov = newClass === TankClass.RANGER ? 0.52 : newClass === TankClass.STALKER ? 0.6 : newClass === TankClass.ASSASSIN ? 0.68 : 0.8; 
          tank.spread = 0.03; 
          if (tank.isBot) tank.visionRange = newClass === TankClass.RANGER ? 1600 : newClass === TankClass.STALKER ? 1400 : 1000; 
      }
      else if (newClass === TankClass.MACHINE_GUN || newClass === TankClass.SPRAYER || newClass === TankClass.GUNNER || newClass === TankClass.AUTO_5 || newClass === TankClass.AUTO_3) { 
          tank.fov = 1.0; 
          tank.spread = newClass === TankClass.GUNNER ? 0.18 : newClass === TankClass.AUTO_5 ? 0.12 : 0.32; 
          if (tank.isBot) tank.visionRange = 700; 
      }
      else if (newClass === TankClass.DESTROYER || newClass === TankClass.HYBRID || newClass === TankClass.ANNIHILATOR) { 
          tank.fov = newClass === TankClass.ANNIHILATOR ? 0.92 : 0.95; 
          tank.spread = 0.08; 
          if (tank.isBot) tank.visionRange = 850; 
      }
      else if (newClass === TankClass.TRI_ANGLE || newClass === TankClass.BOOSTER || newClass === TankClass.FIGHTER) { 
          tank.fov = 1.1; 
          tank.spread = 0.12; 
          if (tank.isBot) tank.visionRange = 800; 
      }
      else if (newClass === TankClass.SMASHER || newClass === TankClass.MEGA_SMASHER || newClass === TankClass.LANDMINE) {
          tank.fov = 1.1;
          tank.mass = newClass === TankClass.MEGA_SMASHER ? 120 : 80;
          if (tank.isBot) tank.visionRange = 600;
      }
      else { tank.fov = 1.0; tank.spread = 0.15; if (tank.isBot) tank.visionRange = 700; }

      tank.updateStats();
      tank.barrelCooldowns = new Array(tank.barrels.length).fill(0);
      tank.barrelMaxCooldowns = new Array(tank.barrels.length).fill(100);
      if (newClass === TankClass.TWIN || newClass === TankClass.TRIPLE_TWIN) {
          tank.barrelCooldowns[1] = 100;
          if (newClass === TankClass.TRIPLE_TWIN) { tank.barrelCooldowns[3] = 100; tank.barrelCooldowns[5] = 100; }
      }
  }

  draw() {
    this.ctx.fillStyle = this.darkMode ? '#0f0f0f' : '#b4b4b4'; 
    this.ctx.fillRect(0, 0, window.innerWidth, window.innerHeight); 

    this.ctx.save();
    this.ctx.translate(window.innerWidth / 2, window.innerHeight / 2); 
    this.ctx.scale(this.cameraZoom, this.cameraZoom); 
    this.ctx.translate(-this.cameraPos.x, -this.cameraPos.y);

    // Draw background
    this.drawGrid(this.ctx); 
    this.ctx.strokeStyle = '#555'; this.ctx.lineWidth = 10; this.ctx.strokeRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

    // Render Optimization: Filter visible entities FIRST, then sort.
    // This dramatically reduces sorting overhead (from 2000+ items to ~50-100 items).
    const visibleEntities = this.entities.filter(e => this.isOnScreen(e.pos, e.radius));

    const sorted = visibleEntities.sort((a, b) => { 
        // Simple priority sort
        const order = { [EntityType.SHAPE]: 1, [EntityType.CRASHER]: 1, [EntityType.BULLET]: 2, [EntityType.ENEMY]: 3, [EntityType.PLAYER]: 4, [EntityType.GUARDIAN]: 5, [EntityType.BOSS]: 6 }; 
        return (order[a.type] || 0) - (order[b.type] || 0); 
    });

    sorted.forEach(e => e.draw(this.ctx));

    this.particles.forEach(p => {
        if (this.isOnScreen(p.pos, p.size)) p.draw(this.ctx);
    });

    this.floatingTexts.forEach(ft => ft.draw(this.ctx)); 
    this.ctx.restore();
  }

  drawGrid(ctx: CanvasRenderingContext2D) {
      const viewW = window.innerWidth / this.cameraZoom;
      const viewH = window.innerHeight / this.cameraZoom;
      const startX = Math.max(0, Math.floor((this.cameraPos.x - viewW/2) / GRID_SIZE) * GRID_SIZE);
      const endX = Math.min(CANVAS_WIDTH, Math.ceil((this.cameraPos.x + viewW/2) / GRID_SIZE) * GRID_SIZE);
      const startY = Math.max(0, Math.floor((this.cameraPos.y - viewH/2) / GRID_SIZE) * GRID_SIZE);
      const endY = Math.min(CANVAS_HEIGHT, Math.ceil((this.cameraPos.y + viewH/2) / GRID_SIZE) * GRID_SIZE);

      if (this.gameMode === GameMode.TEAMS) {
          ctx.fillStyle = 'rgba(0, 178, 225, 0.1)'; ctx.fillRect(0, 0, BASE_ZONE_WIDTH, CANVAS_HEIGHT);
          ctx.fillStyle = 'rgba(241, 78, 84, 0.1)'; ctx.fillRect(CANVAS_WIDTH - BASE_ZONE_WIDTH, 0, BASE_ZONE_WIDTH, CANVAS_HEIGHT);
      }

      ctx.beginPath(); ctx.arc(CANVAS_WIDTH/2, CANVAS_HEIGHT/2, 1500, 0, Math.PI*2); ctx.fillStyle = 'rgba(118, 141, 252, 0.05)'; ctx.fill(); 
      ctx.strokeStyle = 'rgba(118, 141, 252, 0.2)'; ctx.lineWidth = 10; ctx.setLineDash([50, 30]); ctx.stroke(); ctx.setLineDash([]);

      ctx.strokeStyle = this.darkMode ? '#222222' : COLORS.background; ctx.lineWidth = 1; ctx.beginPath();
      for (let x = startX; x <= endX; x += GRID_SIZE) { ctx.moveTo(x, startY); ctx.lineTo(x, endY); }
      for (let y = startY; y <= endY; y += GRID_SIZE) { ctx.moveTo(startX, y); ctx.lineTo(endX, y); }
      ctx.stroke();
  }
}

