import { GoogleGenAI } from "@google/genai";
import { GameState, TankClass } from "../types";

const MODEL_NAME = 'gemini-3-pro-preview';

export class AiService {
    private client: GoogleGenAI;

    constructor() {
        // @ts-ignore - Process.env is injected by the environment
        this.client = new GoogleGenAI({ apiKey: process.env.API_KEY });
    }

    private buildSystemPrompt(gameState: GameState | null): string {
        const context = gameState ? `
        CURRENT COMBAT TELEMETRY:
        - Class: ${gameState.currentClass} (Level ${gameState.level})
        - Score: ${gameState.score}
        - Health: ${Math.round(gameState.health)}/${gameState.maxHealth}
        - Game Mode: ${gameState.gameMode}
        - Build: ${JSON.stringify(gameState.stats)}
        ` : 'NO TELEMETRY AVAILABLE';

        return `You are T.A.C.O.S (Tactical Armored Combat Operations System), an advanced AI advisor for a high-stakes tank combat simulation. 
        Your goal is to provide strategic, concise, and actionable advice to the pilot.

        ${context}

        Analyze the user's query with deep tactical reasoning. Consider positioning, counter-play, and optimal stat builds.`;
    }

    async *streamTacticalAnalysis(query: string, gameState: GameState | null, retries = 3) {
        const fullPrompt = `${this.buildSystemPrompt(gameState)}\n\nPILOT QUERY: ${query}`;

        let attempt = 0;

        while (attempt < retries) {
            try {
                const response = await this.client.models.generateContentStream({
                    model: MODEL_NAME,
                    contents: fullPrompt,
                    config: {
                        thinkingConfig: { thinkingBudget: 32768 },
                        // Explicitly NOT setting maxOutputTokens to prevent truncation of deep thought chains
                    }
                });

                for await (const chunk of response) {
                    yield chunk.text;
                }
                return;

            } catch (error: any) {
                // Handle Rate Limiting (429) Gracefully
                if (error.status === 429 || error.message?.includes('429')) {
                    attempt++;
                    const delay = Math.pow(2, attempt) * 1000 + (Math.random() * 500);
                    console.warn(`[AI SYSTEM] Rate limit detected. Rerouting circuits in ${delay.toFixed(0)}ms...`);

                    if (attempt === retries) {
                        yield "\n\n[SYSTEM CRITICAL] Neural link unstable. Maximum retry attempts exceeded. Please standby.";
                        throw error;
                    }

                    await new Promise(resolve => setTimeout(resolve, delay));
                } else {
                    console.error("[AI SYSTEM] Unexpected Failure:", error);
                    yield `\n\n[SYSTEM ERROR] ${error.message}`;
                    throw error;
                }
            }
        }
    }
}

