import { Vector2 } from '../types';

// Safe number check
const safe = (n: number, fallback = 0): number => (Number.isFinite(n) && !Number.isNaN(n)) ? n : fallback;

export const add = (v1: Vector2, v2: Vector2): Vector2 => ({ x: safe(v1.x + v2.x), y: safe(v1.y + v2.y) });
export const sub = (v1: Vector2, v2: Vector2): Vector2 => ({ x: safe(v1.x - v2.x), y: safe(v1.y - v2.y) });
export const mult = (v: Vector2, n: number): Vector2 => ({ x: safe(v.x * n), y: safe(v.y * n) });
export const div = (v: Vector2, n: number): Vector2 => {
    const safeN = (n === 0 || !Number.isFinite(n)) ? 0.0001 : n;
    return { x: safe(v.x / safeN), y: safe(v.y / safeN) };
};
export const mag = (v: Vector2): number => safe(Math.sqrt(v.x * v.x + v.y * v.y));
export const normalize = (v: Vector2): Vector2 => {
  const m = mag(v);
  return m === 0 ? { x: 0, y: 0 } : { x: safe(v.x / m), y: safe(v.y / m) };
};
export const dist = (v1: Vector2, v2: Vector2): number => mag(sub(v1, v2));
export const clamp = (val: number, min: number, max: number) => Math.min(Math.max(safe(val), min), max);
export const limit = (v: Vector2, max: number): Vector2 => {
    const m = mag(v);
    if (m > max && m > 0) {
        return mult(div(v, m), max);
    }
    return v;
};
export const dot = (v1: Vector2, v2: Vector2): number => safe(v1.x * v2.x + v1.y * v2.y);
export const fromAngle = (angle: number): Vector2 => ({ x: safe(Math.cos(angle)), y: safe(Math.sin(angle)) });

export const randomRange = (min: number, max: number) => Math.random() * (max - min) + min;
export const randomPos = (width: number, height: number): Vector2 => ({
  x: randomRange(0, width),
  y: randomRange(0, height),
});

