type FloatingTextType = 'DAMAGE' | 'SCORE';

class Particle {
    pos: Vector2;
    vel: Vector2;
    color: string;
    life: number;
    maxLife: number;
    size: number;
    friction: number = 0.95;

    constructor(x: number, y: number, color: string, size: number, life: number = 60) {
        this.pos = { x, y };
        const angle = Math.random() * Math.PI * 2;
        const speed = Math.random() * 4 + 2;
        this.vel = { x: Math.cos(angle) * speed, y: Math.sin(angle) * speed };
        this.color = color;
        this.size = size;
        this.maxLife = life;
        this.life = life;
    }

    update() {
        this.pos.x += this.vel.x;
        this.pos.y += this.vel.y;
        this.vel.x *= this.friction;
        this.vel.y *= this.friction;
        this.life--;
    }

    draw(ctx: CanvasRenderingContext2D) {
        if (this.life <= 0) return;
        ctx.globalAlpha = Math.max(0, this.life / this.maxLife);
        ctx.fillStyle = this.color;
        ctx.beginPath();
        ctx.arc(this.pos.x, this.pos.y, this.size, 0, Math.PI * 2);
        ctx.fill();
        ctx.globalAlpha = 1.0;
    }
}

class FloatingText {
    pos: Vector2;
    vel: Vector2;
    text: string;
    value: number;
    entityId: number | null;
    fillColor: string;
    strokeColor: string;
    life: number;
    maxLife: number;
    size: number;
    type: FloatingTextType;
    scale: number;

    constructor(x: number, y: number, amount: number, type: FloatingTextType, size: number, isCrit: boolean = false, entityId: number | null = null) {
        this.pos = { x, y };
        this.value = amount;
        this.text = type === 'DAMAGE' ? `-${Math.floor(amount)}` : `+${Math.floor(amount)} XP`;
        this.type = type;
        this.size = size;
        this.entityId = entityId;
        this.scale = 1.0;

        if (type === 'DAMAGE') {
            this.maxLife = 60; // Reduced life for performance
            this.fillColor = isCrit ? '#ffffff' : '#ffffff';
            this.strokeColor = isCrit ? '#e74c3c' : '#4a4a4a';
            this.vel = { x: 0, y: -0.5 };
        } else {
            this.maxLife = 60; 
            this.fillColor = '#FFD700';
            this.strokeColor = '#000000';
            this.vel = { x: 0, y: -0.8 }; 
        }
        this.life = this.maxLife;
    }

    stack(amount: number) {
        this.value += amount;
        this.text = `-${Math.floor(this.value)}`;
        this.life = this.maxLife;
        this.scale = 1.3;
    }

    update() {
        this.pos.x += this.vel.x;
        this.pos.y += this.vel.y;
        this.life--;
        if (this.scale > 1.0) this.scale -= 0.05;
    }

    draw(ctx: CanvasRenderingContext2D) {
        if (this.life <= 0) return;
        ctx.save();
        let alpha = 1;
        if (this.life < 15) alpha = this.life / 15;
        ctx.globalAlpha = alpha;
        ctx.translate(this.pos.x, this.pos.y);
        ctx.scale(this.scale, this.scale);
        ctx.font = `900 ${this.size}px Ubuntu, sans-serif`;
        ctx.textAlign = 'center';
        ctx.fillStyle = this.fillColor;
        ctx.strokeStyle = this.strokeColor;
        ctx.lineWidth = 3;
        ctx.strokeText(this.text, 0, 0);
        ctx.fillText(this.text, 0, 0);
        ctx.restore();
    }
}

class Entity {
  id: number;
  type: EntityType;
  team: Team = Team.NONE;
  pos: Vector2;
  vel: Vector2;
  acc: Vector2;
  radius: number;
  color: string;
  rotation: number;
  health: number;
  maxHealth: number;
  displayHealth: number;
  shield: number = 0;
  maxShield: number = 0;
  damage: number; 
  isDead: boolean = false;
  lastDamageTime: number = 0;
  mass: number = 1;
  name: string = '';
  friction: number = 0.93; 
  invulnerableTime: number = 0;
  visualScale: number = 1.0;

  constructor(id: number, type: EntityType, x: number, y: number, radius: number, color: string) {
    this.id = id;
    this.type = type;
    this.pos = { x, y };
    this.vel = { x: 0, y: 0 };
    this.acc = { x: 0, y: 0 };
    this.radius = radius;
    this.color = color;
    this.rotation = 0;
    this.health = 100;
    this.maxHealth = 100;
    this.displayHealth = 100;
    this.damage = 10;
    this.mass = radius; 
  }

  update(dt: number) {
    const timeScale = Math.min(dt * 60, 2.0); // Cap physics steps to avoid huge jumps

    if (this.invulnerableTime > 0) this.invulnerableTime -= dt * 1000;
    if (Math.abs(this.displayHealth - this.health) > 0.1) this.displayHealth += (this.health - this.displayHealth) * 0.2;
    else this.displayHealth = this.health;

    this.vel.x += this.acc.x * timeScale;
    this.vel.y += this.acc.y * timeScale;
    this.acc = { x: 0, y: 0 };
    const frictionFactor = Math.pow(this.friction, timeScale);
    this.vel.x *= frictionFactor;
    this.vel.y *= frictionFactor;
    this.pos.x += this.vel.x * timeScale;
    this.pos.y += this.vel.y * timeScale;
    this.pos.x = Vector.clamp(this.pos.x, this.radius, CANVAS_WIDTH - this.radius);
    this.pos.y = Vector.clamp(this.pos.y, this.radius, CANVAS_HEIGHT - this.radius);

    // Deadzone
    if (Math.abs(this.vel.x) < 0.01) this.vel.x = 0;
    if (Math.abs(this.vel.y) < 0.01) this.vel.y = 0;
  }

  draw(ctx: CanvasRenderingContext2D) {
    // Only draw basics here, specific entities override
    ctx.save();
    if (this.invulnerableTime > 0) ctx.globalAlpha = 0.5;
    ctx.translate(this.pos.x, this.pos.y);
    ctx.rotate(this.rotation);
    this.drawBody(ctx);
    ctx.restore();
  }

  drawBody(ctx: CanvasRenderingContext2D) {
    ctx.beginPath();
    ctx.arc(0, 0, this.radius, 0, Math.PI * 2);
    ctx.fillStyle = this.color;
    ctx.fill();
    ctx.lineWidth = 3;
    ctx.strokeStyle = COLORS.border;
    ctx.stroke();
  }

  drawHealthBar(ctx: CanvasRenderingContext2D) {
    const barWidth = this.radius * 2;
    const barHeight = 4;
    const yOffset = this.radius + 12;
    ctx.fillStyle = '#333';
    ctx.fillRect(this.pos.x - barWidth / 2, this.pos.y + yOffset, barWidth, barHeight);
    const hpPct = Math.max(0, this.displayHealth / this.maxHealth);
    ctx.fillStyle = '#6f6';
    ctx.fillRect(this.pos.x - barWidth / 2, this.pos.y + yOffset, barWidth * hpPct, barHeight);
  }

  takeDamage(amount: number, sourceId: number | null = null) {
    if (this.invulnerableTime > 0) return;
    this.lastDamageTime = Date.now();
    if (this.shield > 0) {
        if (amount <= this.shield) { this.shield -= amount; return; }
        else { amount -= this.shield; this.shield = 0; }
    }
    this.health -= amount;
    if (this.health <= 0) { this.isDead = true; this.displayHealth = 0; }
  }
}

class Tank extends Entity {
  classType: TankClass = TankClass.BASIC;
  stats: Record<StatType, number>;
  barrels: number[][]; 
  barrelCooldowns: number[];
  barrelMaxCooldowns: number[];
  score: number = 0;
  availableStatPoints: number = 0;
  isBot: boolean = false;
  aiState: 'IDLE' | 'FARM' | 'COMBAT' | 'FLEE' = 'IDLE';
  visionRange: number = 700;
  autoFire: boolean = false;
  autoSpin: boolean = false;
  fov: number = 1.0;
  spread: number = 0.1;
  nextAiUpdate: number = 0;
  aiMoveDir: Vector2 = { x: 0, y: 0 };
  aiTargetRot: number = 0;
  aiShooting: boolean = false;

  constructor(id: number, x: number, y: number, isPlayer: boolean, team: Team) {
    super(id, isPlayer ? EntityType.PLAYER : EntityType.ENEMY, x, y, 20, isPlayer ? COLORS.player : (team === Team.RED ? COLORS.enemy : COLORS.player));
    this.team = team;
    this.isBot = !isPlayer;
    this.mass = 30;
    this.stats = { [StatType.REGEN]: 0, [StatType.MAX_HEALTH]: 0, [StatType.MAX_SHIELD]: 0, [StatType.BODY_DAMAGE]: 0, [StatType.BULLET_SPEED]: 0, [StatType.BULLET_PENETRATION]: 0, [StatType.BULLET_DAMAGE]: 0, [StatType.RELOAD]: 0, [StatType.MOVEMENT_SPEED]: 0, [StatType.BULLET_SPREAD]: 0 };
    this.barrels = TANK_CONFIGS[TankClass.BASIC];
    this.barrelCooldowns = new Array(this.barrels.length).fill(0);
    this.barrelMaxCooldowns = new Array(this.barrels.length).fill(100);
    this.nextAiUpdate = Math.random() * 500;
  }

  updateStats() {
    this.maxHealth = BASE_STATS.health + (this.stats[StatType.MAX_HEALTH] * 20);
    this.maxShield = this.stats[StatType.MAX_SHIELD] * 20; 
    this.damage = BASE_STATS.bodyDamage + (this.stats[StatType.BODY_DAMAGE] * 5);
    if (this.health > this.maxHealth) this.health = this.maxHealth;
  }

  override update(dt: number) {
    super.update(dt);
    for(let i=0; i<this.barrelCooldowns.length; i++) { 
        if (this.barrelCooldowns[i] > 0) this.barrelCooldowns[i] -= dt * 1000; 
    }
    const timeSinceDamage = Date.now() - this.lastDamageTime;
    if (timeSinceDamage > 3000) {
      const regenRate = BASE_STATS.regen + (this.stats[StatType.REGEN] * 0.04);
      this.health = Math.min(this.health + regenRate, this.maxHealth);
    }
  }

  override drawBody(ctx: CanvasRenderingContext2D) {
    this.barrels.forEach((barrel, i) => {
      const [length, width, xOff, angleOff, , yOff = 0] = barrel;
      ctx.save();
      ctx.translate(0, yOff * this.radius);
      ctx.rotate(angleOff);
      ctx.translate(xOff * this.radius, 0);

      // Simpler recoil calc
      const cooldown = Math.max(0, this.barrelCooldowns[i] || 0);
      const maxCd = this.barrelMaxCooldowns[i] || 100;
      const recoil = (cooldown / maxCd) * (this.radius * 0.2); 
      ctx.translate(-recoil, 0);

      ctx.fillStyle = COLORS.barrel;
      ctx.strokeStyle = COLORS.border;
      ctx.lineWidth = 3;
      ctx.fillRect(0, -(width * this.radius)/2, length * this.radius, width * this.radius);
      ctx.strokeRect(0, -(width * this.radius)/2, length * this.radius, width * this.radius);
      ctx.restore();
    });
    super.drawBody(ctx);
  }
}

class Shape extends Entity {
  shapeType: ShapeType;
  xpValue: number;
  rarity: ShapeRarity;
  damageDealtBy: Map<number, number> = new Map();

  constructor(id: number, x: number, y: number, type: ShapeType) {
    const stats = SHAPE_STATS[type];
    super(id, EntityType.SHAPE, x, y, stats.radius, stats.color);
    this.shapeType = type;
    this.rarity = ShapeRarity.COMMON; // Simplify for crash fix, add rarity back if stable
    this.maxHealth = stats.health;
    this.health = this.maxHealth;
    this.displayHealth = this.maxHealth;
    this.xpValue = stats.xp;
    this.damage = stats.damage; 
    this.mass = this.radius * 2.5;
    this.friction = 0.95;
  }

  override takeDamage(amount: number, sourceId: number | null = null) {
      if (sourceId !== null && amount > 0) this.damageDealtBy.set(sourceId, (this.damageDealtBy.get(sourceId) || 0) + amount);
      super.takeDamage(amount, sourceId);
  }

  override update(dt: number) {
    this.rotation += 0.01;
    this.vel.x *= 0.95; // Simple drag
    this.vel.y *= 0.95;
    super.update(dt);
  }

  override drawBody(ctx: CanvasRenderingContext2D) {
    const sides = SHAPE_STATS[this.shapeType].sides;
    ctx.beginPath();
    for (let i = 0; i < sides; i++) {
        const angle = (i * 2 * Math.PI) / sides;
        ctx.lineTo(Math.cos(angle) * this.radius, Math.sin(angle) * this.radius);
    }
    ctx.closePath();
    ctx.fillStyle = this.color;
    ctx.fill();
    ctx.lineWidth = 3;
    ctx.strokeStyle = COLORS.border;
    ctx.stroke();
  }
}

class Bullet extends Entity {
  ownerId: number;
  lifeTime: number = 0;
  maxLifeTime: number = 3000;

  constructor(id: number, x: number, y: number, velocity: Vector2, owner: Tank, extraDamage: number, extraLife: number, extraSize: number) {
    const size = (6 + (owner.stats[StatType.BULLET_DAMAGE] * 0.3)) * extraSize;
    super(id, EntityType.BULLET, x, y, size, owner.color); // Use owner color directly
    this.team = owner.team;
    this.vel = velocity;
    this.ownerId = owner.id;
    this.mass = size * 0.8; 
    this.damage = (BASE_STATS.bulletDamage + (owner.stats[StatType.BULLET_DAMAGE] * 3)) * extraDamage;
    const penetration = BASE_STATS.bulletPenetration + (owner.stats[StatType.BULLET_PENETRATION] * 5); 
    this.maxHealth = (10 + penetration * 3) * extraDamage;
    this.health = this.maxHealth;
    this.displayHealth = this.maxHealth;
    this.maxLifeTime = 3000 * extraLife;
  }

  override update(dt: number) { 
    super.update(dt); 
    this.lifeTime += dt * 1000; 
    if (this.lifeTime > this.maxLifeTime) this.isDead = true; 
  }
}

class SpatialGrid {
    cellSize: number;
    cells: Map<string, Entity[]> = new Map();

    constructor(cellSize: number) {
        this.cellSize = cellSize;
    }

    private getKey(x: number, y: number) {
        if (!Number.isFinite(x) || !Number.isFinite(y)) return "0,0";
        const cx = Math.floor(x / this.cellSize);
        const cy = Math.floor(y / this.cellSize);
        return `${cx},${cy}`;
    }

    clear() {
        this.cells.clear();
    }

    add(entity: Entity) {
        const key = this.getKey(entity.pos.x, entity.pos.y);
        if (!this.cells.has(key)) this.cells.set(key, []);
        this.cells.get(key)!.push(entity);
    }

    query(pos: Vector2, range: number): Entity[] {
        const results: Entity[] = [];
        const startX = Math.floor((pos.x - range) / this.cellSize);
        const endX = Math.floor((pos.x + range) / this.cellSize);
        const startY = Math.floor((pos.y - range) / this.cellSize);
        const endY = Math.floor((pos.y + range) / this.cellSize);

        // Safety cap to prevent checking too many cells
        if (endX - startX > 10 || endY - startY > 10) return results;

        for (let x = startX; x <= endX; x++) {
            for (let y = startY; y <= endY; y++) {
                const cell = this.cells.get(`${x},${y}`);
                if (cell) {
                    for (const e of cell) results.push(e);
                }
            }
        }
        return results;
    }
}

export class GameEngine {
  canvas: HTMLCanvasElement;
  ctx: CanvasRenderingContext2D;
  entities: Entity[] = [];
  particles: Particle[] = [];
  floatingTexts: FloatingText[] = [];
  player: Tank;
  keys: Set<string> = new Set();
  mouse: Vector2 = { x: 0, y: 0 };
  mouseDown: boolean = false;
  lastTime: number = 0;
  idCounter: number = 0;
  onStateUpdate: (state: GameState) => void;
  spatialGrid: SpatialGrid;
  lastUiUpdate: number = 0;
  cameraPos: Vector2 = { x: 0, y: 0 };
  sound: SoundEngine;

  constructor(canvas: HTMLCanvasElement, onStateUpdate: (state: GameState) => void, onGameOver: any, gameMode: GameMode) {
    this.canvas = canvas;
    this.ctx = canvas.getContext('2d')!;
    this.onStateUpdate = onStateUpdate;
    this.sound = new SoundEngine();
    this.player = new Tank(this.nextId(), CANVAS_WIDTH / 2, CANVAS_HEIGHT / 2, true, Team.BLUE);
    this.entities.push(this.player);
    this.spatialGrid = new SpatialGrid(300); // Larger cells = fewer lookups

    // Initial Spawn
    for (let i = 0; i < 50; i++) this.spawnShape();
  }

  nextId() { return ++this.idCounter; }

  // Stubs for compatibility
  setPlayerName(n: string) { this.player.name = n; }
  setPlayerColor(c: string) { this.player.color = c; }
  setPlayerTeam(t: Team) {}
  setGameMode(m: GameMode) {}
  setDarkMode(b: boolean) {}
  setAttractMode(b: boolean) {}
  toggleAutoFire() { this.player.autoFire = !this.player.autoFire; }
  toggleAutoSpin() { this.player.autoSpin = !this.player.autoSpin; }
  upgradeStat(t: Tank, s: StatType) { if(t.availableStatPoints > 0) { t.stats[s]++; t.availableStatPoints--; t.updateStats(); } }
  upgradeClass(c: TankClass) { this.player.classType = c; this.player.barrels = TANK_CONFIGS[c]; }
  handleInput(k: Set<string>, m: Vector2, d: boolean) { this.keys = k; this.mouse = m; this.mouseDown = d; }
  resetPlayer(pw: boolean) { 
      this.player.isDead = false; 
      this.player.health = this.player.maxHealth; 
      this.player.pos = Vector.randomPos(CANVAS_WIDTH, CANVAS_HEIGHT);
      if(!this.entities.includes(this.player)) this.entities.push(this.player);
  }

  start() { this.lastTime = performance.now(); this.loop(); }

  loop = () => {
      const now = performance.now();
      let dt = (now - this.lastTime) / 1000;
      this.lastTime = now;

      // Safety cap for lag spikes
      if (dt > 0.1) dt = 0.1; 

      this.update(dt);
      this.draw();
      requestAnimationFrame(this.loop);
  }

  update(dt: number) {
    // 1. Clean up dead entities
    this.entities = this.entities.filter(e => !e.isDead);

    // 2. Spatial Grid Rebuild
    this.spatialGrid.clear();
    for (const e of this.entities) this.spatialGrid.add(e);

    // 3. Update Entities
    for (const e of this.entities) {
        if (e.type === EntityType.ENEMY) this.updateBotAI(e as Tank);
        e.update(dt);
    }

    // 4. Update Player Controls
    if (!this.player.isDead) this.updatePlayerControl(dt);

    // 5. Collisions - Only check nearby
    // Using a simple n^2 check ONLY on the players neighborhood for this lightweight version
    // Full implementation would use spatial grid neighbors
    const checkList = this.spatialGrid.query(this.player.pos, 1500); // Only process physics near player
    for (let i = 0; i < checkList.length; i++) {
        for (let j = i + 1; j < checkList.length; j++) {
            const a = checkList[i];
            const b = checkList[j];
            const dist = Vector.dist(a.pos, b.pos);
            if (dist < a.radius + b.radius) {
                this.resolveCollision(a, b);
            }
        }
    }

    // 6. Spawning (Throttled)
    if (Math.random() < 0.05 && this.entities.length < 300) {
        if (Math.random() < 0.8) this.spawnShape();
        else if (this.entities.filter(e => e.type === EntityType.ENEMY).length < 10) this.spawnEnemy();
    }

    // 7. Particles & Text
    this.particles.forEach(p => p.update());
    this.particles = this.particles.filter(p => p.life > 0).slice(0, 50); // Hard cap 50
    this.floatingTexts.forEach(t => t.update());
    this.floatingTexts = this.floatingTexts.filter(t => t.life > 0).slice(0, 20); // Hard cap 20

    // 8. UI Update (Throttled)
    if (Date.now() - this.lastUiUpdate > 100) {
        this.onStateUpdate({
            score: this.player.score,
            level: this.player.level || 1,
            xp: this.xp || 0,
            maxXp: 1000,
            stats: this.player.stats,
            availableStatPoints: this.player.availableStatPoints,
            currentClass: this.player.classType,
            isDead: this.player.isDead,
            fps: Math.round(1/dt),
            health: this.player.displayHealth,
            maxHealth: this.player.maxHealth,
            playerPos: this.player.pos,
            // ... other stubs
            killFeed: [],
            leaderboard: [],
            notifications: [],
            shield: 0, maxShield: 0,
            playerRotation: this.player.rotation,
            camera: { x: this.player.pos.x, y: this.player.pos.y, zoom: 1 },
            mapSize: { width: CANVAS_WIDTH, height: CANVAS_HEIGHT },
            gameMode: GameMode.FFA,
            autoFire: false,
            autoSpin: false
        } as any);
        this.lastUiUpdate = Date.now();
    }
  }

  updatePlayerControl(dt: number) {
      const move = { x: 0, y: 0 };
      if (this.keys.has('w')) move.y -= 1;
      if (this.keys.has('s')) move.y += 1;
      if (this.keys.has('a')) move.x -= 1;
      if (this.keys.has('d')) move.x += 1;
      if (Vector.mag(move) > 0) this.player.acc = Vector.mult(Vector.normalize(move), BASE_STATS.speed * 20);

      const mouseRel = Vector.sub(this.mouse, {x: window.innerWidth/2, y: window.innerHeight/2});
      this.player.rotation = Math.atan2(mouseRel.y, mouseRel.x);

      if (this.mouseDown || this.player.autoFire) {
          this.attemptShoot(this.player);
      }
  }

  updateBotAI(bot: Tank) {
      if (Date.now() < bot.nextAiUpdate) return;
      bot.nextAiUpdate = Date.now() + 500 + Math.random() * 500; // Throttle 0.5s - 1s

      const targets = this.spatialGrid.query(bot.pos, 600);
      const enemy = targets.find(e => e.type === EntityType.PLAYER && !e.isDead);

      if (enemy) {
          const dir = Vector.normalize(Vector.sub(enemy.pos, bot.pos));
          bot.acc = Vector.mult(dir, BASE_STATS.speed * 10);
          bot.rotation = Math.atan2(dir.y, dir.x);
          this.attemptShoot(bot);
      } else {
          // Wander
          bot.acc = Vector.mult(Vector.fromAngle(Math.random() * Math.PI * 2), BASE_STATS.speed * 5);
      }
  }

  attemptShoot(tank: Tank) {
      tank.barrels.forEach((b, i) => {
          if ((tank.barrelCooldowns[i] || 0) <= 0) {
              const angle = tank.rotation + b[3];
              const vel = Vector.mult(Vector.fromAngle(angle), BASE_STATS.bulletSpeed * 10);
              const pos = Vector.add(tank.pos, Vector.mult(Vector.fromAngle(angle), tank.radius * 1.5));
              this.entities.push(new Bullet(this.nextId(), pos.x, pos.y, vel, tank, 1, 1, 1));
              tank.barrelCooldowns[i] = 30; // 0.5s cooldown
          }
      });
  }

  spawnShape() {
      const pos = Vector.randomPos(CANVAS_WIDTH, CANVAS_HEIGHT);
      this.entities.push(new Shape(this.nextId(), pos.x, pos.y, ShapeType.SQUARE));
  }

  spawnEnemy() {
      const pos = Vector.randomPos(CANVAS_WIDTH, CANVAS_HEIGHT);
      this.entities.push(new Tank(this.nextId(), pos.x, pos.y, false, Team.RED));
  }

  resolveCollision(a: Entity, b: Entity) {
      const dist = Vector.dist(a.pos, b.pos);
      const push = Vector.normalize(Vector.sub(a.pos, b.pos));
      const overlap = (a.radius + b.radius) - dist;

      if (overlap > 0) {
          a.pos = Vector.add(a.pos, Vector.mult(push, overlap * 0.5));
          b.pos = Vector.sub(b.pos, Vector.mult(push, overlap * 0.5));

          if (a.type === EntityType.BULLET) { a.takeDamage(10); b.takeDamage(10); }
          else if (b.type === EntityType.BULLET) { a.takeDamage(10); b.takeDamage(10); }
      }
  }

  findNearest(origin: Entity, targets: Entity[]) {
      if (!targets.length) return null;
      let minDst = Infinity;
      let nearest = null;
      for (const t of targets) {
          const d = Vector.dist(origin.pos, t.pos);
          if (d < minDst) { minDst = d; nearest = t; }
      }
      return nearest;
  }

  draw() {
      this.ctx.fillStyle = this.darkMode ? '#222' : '#cdcdcd';
      this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);

      this.ctx.save();
      this.ctx.translate(this.canvas.width/2 - this.player.pos.x, this.canvas.height/2 - this.player.pos.y);

      // Draw Grid
      this.ctx.strokeStyle = 'rgba(0,0,0,0.1)';
      this.ctx.lineWidth = 1;
      const startX = Math.floor((this.player.pos.x - this.canvas.width/2) / GRID_SIZE) * GRID_SIZE;
      const endX = startX + this.canvas.width;
      const startY = Math.floor((this.player.pos.y - this.canvas.height/2) / GRID_SIZE) * GRID_SIZE;
      const endY = startY + this.canvas.height;

      this.ctx.beginPath();
      for(let x = startX; x < endX; x+=GRID_SIZE) { this.ctx.moveTo(x, startY); this.ctx.lineTo(x, endY); }
      for(let y = startY; y < endY; y+=GRID_SIZE) { this.ctx.moveTo(startX, y); this.ctx.lineTo(endX, y); }
      this.ctx.stroke();

      // Draw Entities
      const viewBuffer = 100;
      const visible = this.entities.filter(e => 
          e.pos.x > this.player.pos.x - this.canvas.width/2 - viewBuffer &&
          e.pos.x < this.player.pos.x + this.canvas.width/2 + viewBuffer &&
          e.pos.y > this.player.pos.y - this.canvas.height/2 - viewBuffer &&
          e.pos.y < this.player.pos.y + this.canvas.height/2 + viewBuffer
      );

      visible.forEach(e => {
          e.draw(this.ctx);
          if(e.type !== EntityType.BULLET && e.health < e.maxHealth) e.drawHealthBar(this.ctx);
      });

      this.particles.forEach(p => p.draw(this.ctx));
      this.floatingTexts.forEach(t => t.draw(this.ctx));

      this.ctx.restore();
  }
}

