         <div className="pointer-events-auto flex flex-col items-center gap-6 bg-black/50 p-12 rounded-3xl backdrop-blur-md border border-white/10">
             <h1 className="text-6xl font-black text-cyan-400 italic">DIEP REMIX</h1>

             <form onSubmit={handleStartGame} className="flex flex-col gap-4 w-full max-w-sm">
                 <input 
                    type="text" 
                    placeholder="ENTER NAME" 
                    value={playerName}
                    onChange={e => setPlayerName(e.target.value)}
                    className="px-6 py-3 rounded-xl bg-black/50 border border-white/20 text-white font-bold text-center focus:outline-none focus:border-cyan-400 transition-colors"
                 />
                 <button className="px-8 py-4 bg-cyan-600 hover:bg-cyan-500 text-white font-black rounded-xl text-xl shadow-lg transition-transform hover:scale-105 active:scale-95">
                     PLAY NOW
                 </button>
             </form>

             <div className="flex gap-4">
                 <button onClick={() => setShowSettings(true)} className="p-3 bg-white/10 rounded-lg hover:bg-white/20 transition-colors">⚙️ Settings</button>
                 <button onClick={() => setShowAlmanac(true)} className="p-3 bg-white/10 rounded-lg hover:bg-white/20 transition-colors">📚 Almanac</button>
                 <button onClick={() => setShowShop(true)} className="p-3 bg-white/10 rounded-lg hover:bg-white/20 transition-colors">🛒 Shop</button>
             </div>
         </div>
      </div>

      {/* Modals */}
      {showSettings && <div className="absolute inset-0 bg-black/80 z-[60] flex items-center justify-center" onClick={() => setShowSettings(false)}>
          <div className="bg-[#111] p-8 rounded-2xl border border-white/10" onClick={e => e.stopPropagation()}>
              <h2 className="text-2xl text-white font-bold mb-4">Settings</h2>
              <div className="flex items-center justify-between gap-8 mb-4">
                  <span className="text-white">Dark Mode</span>
                  <button onClick={() => setSettings(s => ({...s, darkMode: !s.darkMode}))} className={`w-12 h-6 rounded-full p-1 transition-colors ${settings.darkMode ? 'bg-cyan-600' : 'bg-gray-600'}`}>
                      <div className={`w-4 h-4 bg-white rounded-full transition-transform ${settings.darkMode ? 'translate-x-6' : ''}`} />
                  </button>
              </div>
          </div>
      </div>}

      {showAlmanac && <AlmanacModal onClose={() => setShowAlmanac(false)} darkMode={settings.darkMode} />}
      {showShop && <ShopModal user={user} onClose={() => setShowShop(false)} onUpdateUser={setUser} darkMode={settings.darkMode} />}

      {/* AI Modal Removed for Stability */}
    </div>
  );
};

export default App;
